/**
 * EliteUI - Production-ready vanilla JavaScript framework
 * Version 1.0.0
 * Zero runtime dependencies
 */

/**
 * SimpleComponent
 * Base class para todos los componentes del framework.
 *
 * Propiedades:
 * - state: objeto reativo con getter/setter
 * - lifecycle hooks: mount, unmount, update
 * - event delegation: on(), off()
 * - templating: html``
 * - side effects: useEffect()
 *
 * No requiere dependencias externas.
 */

class SimpleComponent {
  constructor(selector, initialState = {}) {
    // Resolver selector
    this.el = typeof selector === 'string'
      ? document.querySelector(selector)
      : selector

    if (!this.el) {
      console.warn(`[SimpleComponent] selector not found:`, selector)
    }

    // Props (immutable from component perspective, updatable from parent)
    this._props = {}

    // Estado reactivo
    this._state = initialState
    this._subscribers = []
    this._effectDependencies = new Map()
    this._prevState = null

    // Lifecycle
    this._mounted = false
    this._unmounted = false

    // Event delegation
    this._eventListeners = []

    // Child components (for automatic cleanup)
    this._children = []

    // Lazy load resources
    this._resources = new Map()
    this._loadingPromises = new Map()

    // Error boundary
    this._errorBoundary = null
  }

  /**
   * Acceso a estado
   */
  get state() {
    return { ...this._state }
  }

  /**
   * Actualizar estado (reactivo)
   * Dispara render + subscribers
   */
  setState(updates) {
    if (typeof updates === 'function') {
      updates = updates(this._state)
    }

    const prevState = this._state
    const hasChanges = Object.keys(updates).some(key =>
      this._state[key] !== updates[key]
    )

    if (!hasChanges) return // No-op si no hay cambios

    this._prevState = prevState
    this._state = { ...this._state, ...updates }

    this.onStateChange?.(this._state, prevState)
    this.render()
    this._processDirectives(this.el)
    this._notifySubscribers(prevState, this._state)
  }

  /**
   * Subscribe to state changes
   * @returns {Function} unsubscribe function
   */
  subscribe(callback) {
    this._subscribers.push(callback)
    return () => {
      this._subscribers = this._subscribers.filter(cb => cb !== callback)
    }
  }

  _notifySubscribers(prev, curr) {
    this._subscribers.forEach(cb => {
      try {
        cb(curr, prev)
      } catch (e) {
        console.error('[SimpleComponent] subscriber error:', e)
      }
    })
  }

  /**
   * Update props reactively (called by parent)
   * Triggers onPropsChange() and re-render if already mounted
   * Uses shouldRender() to allow memoization (similar to React.memo)
   */
  setProps(updates) {
    const prev = { ...this._props }
    const next = { ...this._props, ...updates }
    const hasChanges = Object.keys(updates).some(k => this._props[k] !== updates[k])

    if (!hasChanges) return

    // Check if component wants to render with new props
    if (!this.shouldRender(next, prev)) return

    this._props = next
    this.onPropsChange(this._props, prev)

    if (this._mounted) {
      this.render()
    }
  }

  /**
   * Lifecycle: Props change
   * Override en subclases para reaccionar a cambios de props
   */
  onPropsChange(newProps, prevProps) {
    // Override en subclases
  }

  /**
   * Decide whether to re-render on props change
   * Similar to React.memo - return false to skip render
   * Default: always re-render
   * Override in subclass to implement memoization
   */
  shouldRender(newProps, prevProps) {
    return true
  }

  /**
   * Create a mutable reference that doesn't trigger re-render
   * Similar to React.useRef
   */
  useRef(initialValue = null) {
    if (!this._refs) this._refs = []
    const ref = { current: initialValue }
    this._refs.push(ref)
    return ref
  }

  /**
   * Register child component for automatic cleanup on unmount
   */
  registerChild(component) {
    this._children.push(component)
    return component
  }

  /**
   * Emit custom event that bubbles to parent
   */
  emit(eventName, detail = {}) {
    const event = new CustomEvent(`elite:${eventName}`, {
      detail,
      bubbles: true,
      composed: true
    })
    this.el?.dispatchEvent(event)
  }

  /**
   * Side effects (similar a useEffect)
   * @param {Function} effect
   * @param {Array} dependencies
   */
  useEffect(effect, dependencies = []) {
    // Assign unique key to each effect call to prevent collisions from identical closures
    if (!effect.__eliteEffectKey) {
      effect.__eliteEffectKey = Symbol('elite-effect-' + Date.now() + Math.random())
    }
    const key = effect.__eliteEffectKey

    const prev = this._effectDependencies.get(key) || []

    const hasChanged = dependencies.length === 0 ||
      dependencies.some((dep, i) => dep !== prev[i])

    if (hasChanged) {
      try {
        const cleanup = effect()
        if (typeof cleanup === 'function') {
          // Store cleanup for unmount
          if (!this._cleanups) this._cleanups = []
          this._cleanups.push(cleanup)
        }
      } catch (e) {
        console.error('[SimpleComponent] effect error:', e)
      }
      this._effectDependencies.set(key, dependencies)
    }
  }

  /**
   * Event delegation
   * @param {string} event - 'click', 'change', etc.
   * @param {string} selector - CSS selector
   * @param {Function} handler
   */
  on(event, selector, handler) {
    const listener = (e) => {
      if (e.target.matches(selector)) {
        try {
          handler.call(this, e)
        } catch (err) {
          console.error('[SimpleComponent] event handler error:', err)
        }
      }
    }

    this.el?.addEventListener(event, listener)
    this._eventListeners.push({ event, listener })
  }

  /**
   * Remove event listener
   */
  off(event, handler) {
    this._eventListeners = this._eventListeners.filter(item => {
      if (item.event === event) {
        this.el?.removeEventListener(event, item.listener)
        return false
      }
      return true
    })
  }

  /**
   * Load template from DOM (no fetch for file:// compatibility)
   */
  loadTemplate(templateId) {
    const fullId = `tmpl-${templateId}`
    const tmpl = document.getElementById(fullId)
    
    if (tmpl) {
      return tmpl.innerHTML
    }
    
    console.warn(`[SimpleComponent] Template not found: ${templateId}`)
    return ''
  }

  /**
   * Escape HTML to prevent XSS
   * @param {string} text
   * @returns {string}
   */
  _escapeHtml(text) {
    const div = document.createElement('div')
    div.textContent = text
    return div.innerHTML
  }

  /**
   * Lazy load a resource
   * @param {string} resourceId
   * @param {Function} loader - () => Promise<data>
   */
  async lazyLoad(resourceId, loader) {
    if (this._resources.has(resourceId)) {
      return this._resources.get(resourceId)
    }

    if (this._loadingPromises.has(resourceId)) {
      return this._loadingPromises.get(resourceId)
    }

    const promise = Promise.resolve()
      .then(() => loader())
      .then(data => {
        this._resources.set(resourceId, data)
        return data
      })
      .catch(err => {
        console.error(`[SimpleComponent] lazy load failed (${resourceId}):`, err)
        throw err
      })

    this._loadingPromises.set(resourceId, promise)

    try {
      return await promise
    } finally {
      this._loadingPromises.delete(resourceId)
    }
  }

  /**
   * Set error boundary handler
   */
  setErrorBoundary(handler) {
    this._errorBoundary = handler
  }

  _handleError(error) {
    if (this._errorBoundary) {
      this._errorBoundary(error, this)
    } else {
      console.error('[SimpleComponent] unhandled error:', error)
    }
  }

  /**
   * Lifecycle: Mount
   * Llamado automáticamente en mount()
   */
  onMount() {
    // Override en subclases
  }

  /**
   * Lifecycle: Unmount
   * Llamado automáticamente en unmount()
   */
  onUnmount() {
    // Override en subclases
  }

  /**
   * Lifecycle: State change
   * Llamado cuando setState() actualiza el estado
   */
  onStateChange(newState, prevState) {
    // Override en subclases
  }

  /**
   * Render (debe override)
   */
  render() {
    if (!this.el) return
    console.warn('[SimpleComponent] render() not implemented')
  }

  /**
   * Mount component
   */
  mount() {
    if (this._mounted) return

    const componentName = this.constructor.name

    try {
      $debug?.trackComponent(componentName, 'mount', { selector: this.el?.id || this.el?.className || 'unknown' })
      this.render()
      this._processDirectives(this.el)
      this.onMount()
      this._mounted = true
      $debug?.trackComponent(componentName, 'mounted')
    } catch (e) {
      $debug?.trackComponent(componentName, 'error', { error: e.message })
      this._handleError(e)
    }
  }

  /**
   * Unmount component (cleanup)
   */
  unmount() {
    if (this._unmounted) return

    const componentName = this.constructor.name
    $debug?.trackComponent(componentName, 'unmount')

    try {
      this.onUnmount()

      // Unmount child components
      this._children.forEach(child => {
        try {
          child.unmount()
        } catch (e) {
          $debug?.trackComponent(child.constructor.name, 'error', { error: e.message })
          console.error('[SimpleComponent] child unmount error:', e)
        }
      })
      this._children = []

      // Clean up refs
      if (this._refs) {
        this._refs.forEach(ref => {
          ref.current = null
        })
        this._refs = []
      }

      // Run cleanup functions
      if (this._cleanups) {
        this._cleanups.forEach(cleanup => {
          try {
            cleanup()
          } catch (e) {
            console.error('[SimpleComponent] cleanup error:', e)
          }
        })
      }

      // Remove all event listeners
      this._eventListeners.forEach(({ event, listener }) => {
        this.el?.removeEventListener(event, listener)
      })
      this._eventListeners = []

      // Clear subscribers
      this._subscribers = []

      this._unmounted = true
      $debug?.trackComponent(componentName, 'unmounted')
    } catch (e) {
      $debug?.trackComponent(componentName, 'error', { error: e.message })
      this._handleError(e)
    }
  }

  /**
   * Forzar re-render sin cambiar estado
   */
  forceUpdate() {
    try {
      this.render()
    } catch (e) {
      this._handleError(e)
    }
  }

  /**
   * Evalúa una expresión en el contexto del estado y props del componente
   * @param {string} expr - Expresión JavaScript (ej: "count > 5" o "name === 'John'")
   * @returns {any} Resultado de la evaluación
   */
  _evalExpr(expr) {
    try {
      const state = this._state
      const props = this._props
      // Usamos 'with' para que las claves de state y props estén disponibles en el scope de la expresión
      return new Function('state', 'props', `with(props) { with(state) { return (${expr}) } }`)(state, props)
    } catch (e) {
      console.warn(`[SimpleComponent] expression eval error: "${expr}"`, e.message)
      return undefined
    }
  }

  /**
   * Procesa directivas data-* en el DOM
   * Se llama automáticamente después de cada render()
   *
   * Directivas soportadas:
   * - data-if="expr" → muestra/oculta con display:none
   * - data-show="expr" → muestra/oculta con visibility (mantiene layout)
   * - data-text="key" → escribe state[key] como textContent
   * - data-bind="key" → two-way binding en inputs
   * - data-class-X="expr" → toggle de clase X según expr
   * - data-onclick="method" → llama this[method](e) al hacer click
   * - data-link="/path" → navega sin reload via router
   */
  _processDirectives(root = this.el) {
    if (!root) return

    try {
      // data-if: muestra/oculta con display:none
      root.querySelectorAll('[data-if]').forEach(el => {
        el.style.display = this._evalExpr(el.dataset.if) ? '' : 'none'
      })

      // data-show: muestra/oculta con visibility (mantiene layout)
      root.querySelectorAll('[data-show]').forEach(el => {
        el.style.visibility = this._evalExpr(el.dataset.show) ? '' : 'hidden'
      })

      // data-text: escribe state[key] como textContent (XSS-safe)
      root.querySelectorAll('[data-text]').forEach(el => {
        const key = el.dataset.text
        const val = this._state[key] ?? this._props?.[key] ?? ''
        el.textContent = val
      })

      // data-bind: two-way binding (solo primera vez, luego los listeners persisten)
      root.querySelectorAll('[data-bind]').forEach(el => {
        const key = el.dataset.bind
        const isFormElement = el.tagName === 'INPUT' || el.tagName === 'TEXTAREA' || el.tagName === 'SELECT'

        if (isFormElement) {
          el.value = this._state[key] ?? ''

          // Registrar listener solo una vez (flag privado en el elemento)
          if (!el.__eliteDirectiveBound) {
            el.__eliteDirectiveBound = true
            el.addEventListener('input', e => {
              this.setState({ [key]: e.target.value })
            })
          }
        }
      })

      // data-class-X="expr": toggle de clase según expresión
      root.querySelectorAll('*').forEach(el => {
        Object.keys(el.dataset).forEach(key => {
          if (key.startsWith('class')) {
            // Convertir camelCase a kebab-case para nombres de clase
            // data-classActive -> className "active"
            // data-classIsPrimary -> className "is-primary"
            const className = key
              .slice(5)  // "classActive" -> "Active"
              .replace(/([A-Z])/g, '-$1')  // "Active" -> "-Active"
              .toLowerCase()  // "-active"
              .replace(/^-/, '')  // "active"

            const shouldAdd = this._evalExpr(el.dataset[key])
            el.classList.toggle(className, !!shouldAdd)
          }
        })
      })

      // data-onclick="method": registra click handler
      root.querySelectorAll('[data-onclick]').forEach(el => {
        if (!el.__eliteDirectiveOnclick) {
          el.__eliteDirectiveOnclick = true
          const methodName = el.dataset.onclick

          el.addEventListener('click', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onclick handler error (${methodName}):`, err)
              }
            } else {
              console.warn(`[SimpleComponent] method not found: ${methodName}`)
            }
          })
        }
      })

      // data-link="/path": navega sin reload
      root.querySelectorAll('[data-link]').forEach(el => {
        if (!el.__eliteDirectiveLink) {
          el.__eliteDirectiveLink = true

          el.addEventListener('click', e => {
            e.preventDefault()
            const path = el.dataset.link
            if (window.$router?.navigate) {
              window.$router.navigate(path)
            } else {
              console.warn('[SimpleComponent] Router not available for data-link')
            }
          })
        }
      })

      // data-html: renderiza el resultado de la expresión como HTML (⚠️ XSS risk)
      root.querySelectorAll('[data-html]').forEach(el => {
        const expr = el.dataset.html
        const val = this._evalExpr(expr)
        el.innerHTML = val ?? ''
      })

      // data-disabled="expr": desactiva elemento
      root.querySelectorAll('[data-disabled]').forEach(el => {
        const shouldDisable = this._evalExpr(el.dataset.disabled)
        el.disabled = !!shouldDisable
      })

      // data-value="key": establece value (lectura, no two-way)
      root.querySelectorAll('[data-value]').forEach(el => {
        const key = el.dataset.value
        const val = this._state[key] ?? this._props?.[key] ?? ''
        el.value = val
      })

      // data-checked="expr": para checkboxes/radios
      root.querySelectorAll('[data-checked]').forEach(el => {
        const isChecked = this._evalExpr(el.dataset.checked)
        el.checked = !!isChecked
      })

      // data-placeholder="key": placeholder dinámico
      root.querySelectorAll('[data-placeholder]').forEach(el => {
        const key = el.dataset.placeholder
        const val = this._state[key] ?? this._props?.[key] ?? ''
        el.placeholder = val
      })

      // data-title="key": atributo title dinámico
      root.querySelectorAll('[data-title]').forEach(el => {
        const key = el.dataset.title
        const val = this._state[key] ?? this._props?.[key] ?? ''
        el.title = val
      })

      // data-href="key": href dinámico
      root.querySelectorAll('[data-href]').forEach(el => {
        const key = el.dataset.href
        const val = this._state[key] ?? this._props?.[key] ?? '#'
        el.href = val
      })

      // data-src="key": src dinámico (imágenes, iframes, etc)
      root.querySelectorAll('[data-src]').forEach(el => {
        const key = el.dataset.src
        const val = this._state[key] ?? this._props?.[key] ?? ''
        el.src = val
      })

      // data-attr-*="key": atributos dinámicos genéricos
      // Ejemplo: data-attr-aria-label="message", data-attr-data-id="userId"
      root.querySelectorAll('*').forEach(el => {
        Object.keys(el.dataset).forEach(key => {
          if (key.startsWith('attr')) {
            // data-attrAriaLabel -> aria-label
            // data-attrDataId -> data-id
            const attrName = key
              .slice(4)  // "attrAriaLabel" -> "AriaLabel"
              .replace(/([A-Z])/g, '-$1')  // "AriaLabel" -> "-Aria-Label"
              .toLowerCase()  // "-aria-label"
              .replace(/^-/, '')  // "aria-label"

            const val = this._evalExpr(el.dataset[key])
            el.setAttribute(attrName, val ?? '')
          }
        })
      })

      // data-style-*: estilos dinámicos
      // Ejemplo: data-style-color="color", data-style-font-size="fontSize"
      root.querySelectorAll('*').forEach(el => {
        Object.keys(el.dataset).forEach(key => {
          if (key.startsWith('style')) {
            // data-styleColor -> --color o color
            // data-styleFontSize -> --font-size o fontSize
            let cssKey = key
              .slice(5)  // "styleColor" -> "Color"
              .replace(/([A-Z])/g, '-$1')  // "Color" -> "-Color"
              .toLowerCase()  // "-color"
              .replace(/^-/, '')  // "color"

            // Convertir kebab-case a camelCase para cssText
            const camelKey = cssKey.replace(/-([a-z])/g, (g) => g[1].toUpperCase())

            const val = this._evalExpr(el.dataset[key])
            if (val !== undefined && val !== null) {
              el.style[camelKey] = val
            }
          }
        })
      })

      // data-onchange="method": listener para change events
      root.querySelectorAll('[data-onchange]').forEach(el => {
        if (!el.__eliteDirectiveOnchange) {
          el.__eliteDirectiveOnchange = true
          const methodName = el.dataset.onchange

          el.addEventListener('change', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onchange handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-oninput="method": listener para input events
      root.querySelectorAll('[data-oninput]').forEach(el => {
        if (!el.__eliteDirectiveOninput) {
          el.__eliteDirectiveOninput = true
          const methodName = el.dataset.oninput

          el.addEventListener('input', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] oninput handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-onkeyup="method": listener para keyup events
      root.querySelectorAll('[data-onkeyup]').forEach(el => {
        if (!el.__eliteDirectiveOnkeyup) {
          el.__eliteDirectiveOnkeyup = true
          const methodName = el.dataset.onkeyup

          el.addEventListener('keyup', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onkeyup handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-onkeydown="method": listener para keydown events
      root.querySelectorAll('[data-onkeydown]').forEach(el => {
        if (!el.__eliteDirectiveOnkeydown) {
          el.__eliteDirectiveOnkeydown = true
          const methodName = el.dataset.onkeydown

          el.addEventListener('keydown', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onkeydown handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-onhover="method": listener para mouse enter/leave
      root.querySelectorAll('[data-onhover]').forEach(el => {
        if (!el.__eliteDirectiveOnhover) {
          el.__eliteDirectiveOnhover = true
          const methodName = el.dataset.onhover

          el.addEventListener('mouseenter', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onhover handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-onfocus="method": listener para focus events
      root.querySelectorAll('[data-onfocus]').forEach(el => {
        if (!el.__eliteDirectiveOnfocus) {
          el.__eliteDirectiveOnfocus = true
          const methodName = el.dataset.onfocus

          el.addEventListener('focus', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onfocus handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-onblur="method": listener para blur events
      root.querySelectorAll('[data-onblur]').forEach(el => {
        if (!el.__eliteDirectiveOnblur) {
          el.__eliteDirectiveOnblur = true
          const methodName = el.dataset.onblur

          el.addEventListener('blur', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onblur handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-onsubmit="method": listener para submit events (forms)
      root.querySelectorAll('[data-onsubmit]').forEach(el => {
        if (!el.__eliteDirectiveOnsubmit) {
          el.__eliteDirectiveOnsubmit = true
          const methodName = el.dataset.onsubmit

          el.addEventListener('submit', e => {
            if (typeof this[methodName] === 'function') {
              try {
                this[methodName](e)
              } catch (err) {
                console.error(`[SimpleComponent] onsubmit handler error (${methodName}):`, err)
              }
            }
          })
        }
      })

      // data-permission="permission": muestra/oculta según permisos
      // Uso: data-permission="admin" o data-permission="users.write"
      root.querySelectorAll('[data-permission]').forEach(el => {
        const permission = el.dataset.permission
        const hasPermission = $permissions?.can(permission)
        
        if (hasPermission === false) {
          el.style.display = 'none'
        } else if (hasPermission === true) {
          el.style.display = ''
        }
        // Si $permissions no existe, mostrar elemento por defecto
      })

      // data-role="admin": muestra/oculta según rol
      // Uso: data-role="admin" o data-role="user"
      root.querySelectorAll('[data-role]').forEach(el => {
        const role = el.dataset.role
        const hasRole = $permissions?.isRole(role)
        
        if (hasRole === false) {
          el.style.display = 'none'
        } else if (hasRole === true) {
          el.style.display = ''
        }
      })

      // Auto-resolve child components: <component-name> -> ComponentClass
      this._resolveChildComponents(root)
    } catch (e) {
      console.error('[SimpleComponent] directive processing error:', e)
    }
  }

  /**
   * Auto-mount child components based on custom element names
   * Usage: <hero-component>, <feature-card>, <counter-component>
   * Looks for window.HeroComponent, window.FeatureCard, etc.
   */
  _resolveChildComponents(root) {
    const allElements = root.querySelectorAll('*')
    
    allElements.forEach(el => {
      // Skip elements already processed
      if (el.__eliteComponentResolved) return
      
      const tagName = el.tagName.toLowerCase()
      
      // Only process custom elements (kebab-case with hyphens)
      if (!tagName.includes('-')) return
      
      // Try to find component class
      const componentClass = this._findComponentClass(tagName)
      
      if (componentClass) {
        el.__eliteComponentResolved = true
        
        // Extract props from attributes
        const props = this._extractPropsFromAttributes(el)
        
        console.log(`[SimpleComponent] Mounting ${tagName} with props:`, props)
        
        // Create component instance
        const childComponent = new componentClass(el, props)
        this.registerChild(childComponent)
        childComponent.mount()
      } else {
        console.warn(`[SimpleComponent] Component class not found for: ${tagName}`)
      }
    })
  }

  /**
   * Find component class by tag name
   * <hero-component> -> HeroComponent, Hero
   * <feature-card> -> FeatureCard
   * <counter-component> -> CounterComponent, Counter
   */
  _findComponentClass(tagName) {
    // Try exact match: 'hero-component' -> 'HeroComponent'
    const pascalName = this._kebabToPascal(tagName)
    
    if (window[pascalName]) {
      return window[pascalName]
    }
    
    // Try without '-component' suffix: 'hero-component' -> 'Hero'
    const withoutComponent = tagName.replace('-component', '')
    const shortPascal = this._kebabToPascal(withoutComponent)
    
    if (window[shortPascal]) {
      return window[shortPascal]
    }
    
    return null
  }

  /**
   * Convert kebab-case to PascalCase
   * 'hero-component' -> 'HeroComponent'
   */
  _kebabToPascal(str) {
    return str
      .split('-')
      .map(part => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
      .join('')
  }

  /**
   * Extract props from element attributes
   * <component prop1="value1" prop2="value2">
   */
  _extractPropsFromAttributes(el) {
    const props = {}
    
    for (const attr of el.attributes) {
      // Skip standard attributes that aren't props
      if (['id', 'class', 'style'].includes(attr.name)) continue
      
      // Convert attribute name to prop name (kebab to camelCase)
      const propName = attr.name.replace(/-([a-z])/g, (g) => g[1].toUpperCase())
      
      // Try to parse as JSON, otherwise use string
      try {
        props[propName] = JSON.parse(attr.value)
      } catch {
        props[propName] = attr.value
      }
    }
    
    return props
  }
}

window.SimpleComponent = SimpleComponent

/**
 * MetaManager
 * SEO & Social Media meta tags manager para SPAs
 *
 * Uso:
 * const meta = new MetaManager()
 * meta.setTitle('Página de Productos')
 * meta.setOG({ title, image, description, url })
 * meta.setStructuredData({ '@type': 'Product', ... })
 * meta.generateShareUrl('twitter')
 */

class MetaManager {
  constructor(options = {}) {
    this.defaults = options.default || {}
    this.current = { ...this.defaults }
    this.history = []
  }

  /**
   * Set page title
   */
  setTitle(title) {
    this.current.title = title
    document.title = title
    this._updateMeta('og:title', title)
    this._updateMeta('twitter:title', title)
    return this
  }

  /**
   * Set page description
   */
  setDescription(description) {
    this.current.description = description
    this._updateMeta('description', description)
    this._updateMeta('og:description', description)
    this._updateMeta('twitter:description', description)
    return this
  }

  /**
   * Check if URL is safe (relative or https/http)
   */
  _isSafeUrl(url) {
    if (!url || typeof url !== 'string') return false
    try {
      const parsed = new URL(url, window.location.origin)
      return ['https:', 'http:'].includes(parsed.protocol)
    } catch (e) {
      // If it fails to parse as absolute URL, check if it's a relative URL
      return /^\/[^/]/.test(url) || /^\.\//.test(url) || /^\.\.\//.test(url)
    }
  }

  /**
   * Set canonical URL (important for SEO)
   * Security: validates that URL is relative or https/http
   */
  setCanonical(url) {
    // Validate URL for security
    if (!this._isSafeUrl(url)) {
      console.warn('[MetaManager] Unsafe canonical URL rejected:', url)
      return this
    }

    this.current.canonical = url
    let link = document.querySelector('link[rel="canonical"]')
    if (!link) {
      link = document.createElement('link')
      link.rel = 'canonical'
      document.head.appendChild(link)
    }
    link.href = url
    this._updateMeta('og:url', url)
    return this
  }

  /**
   * Set multiple Open Graph tags at once
   */
  setOG(data) {
    const {
      title,
      description,
      image,
      url,
      type = 'website',
      locale = 'es_ES'
    } = data

    if (title) this._updateMeta('og:title', title)
    if (description) this._updateMeta('og:description', description)
    if (image) this._updateMeta('og:image', image)
    if (url) this._updateMeta('og:url', url)
    this._updateMeta('og:type', type)
    this._updateMeta('og:locale', locale)

    // Twitter specific
    this._updateMeta('twitter:card', 'summary_large_image')
    if (title) this._updateMeta('twitter:title', title)
    if (description) this._updateMeta('twitter:description', description)
    if (image) this._updateMeta('twitter:image', image)

    this.current.og = { ...this.current.og, ...data }
    return this
  }

  /**
   * Set structured data (JSON-LD)
   */
  setStructuredData(data) {
    this.current.structuredData = data

    let script = document.querySelector('script[type="application/ld+json"]')
    if (!script) {
      script = document.createElement('script')
      script.type = 'application/ld+json'
      document.head.appendChild(script)
    }

    script.textContent = JSON.stringify(data)
    return this
  }

  /**
   * Set breadcrumb structured data
   */
  setBreadcrumb(items) {
    const breadcrumb = {
      '@context': 'https://schema.org',
      '@type': 'BreadcrumbList',
      itemListElement: items.map((item, index) => ({
        '@type': 'ListItem',
        position: index + 1,
        name: item.name,
        item: item.url
      }))
    }

    this.setStructuredData(breadcrumb)
    return this
  }

  /**
   * Set product structured data
   */
  setProduct(data) {
    const {
      name,
      description,
      image,
      price,
      currency = 'USD',
      rating,
      reviews,
      availability = 'InStock',
      url
    } = data

    const product = {
      '@context': 'https://schema.org',
      '@type': 'Product',
      name,
      description,
      image: Array.isArray(image) ? image : [image],
      offers: {
        '@type': 'Offer',
        price,
        priceCurrency: currency,
        availability: `https://schema.org/${availability}`
      }
    }

    if (rating) {
      product.aggregateRating = {
        '@type': 'AggregateRating',
        ratingValue: rating.value,
        ratingCount: rating.count
      }
    }

    if (url) {
      product.url = url
    }

    this.setStructuredData(product)
    return this
  }

  /**
   * Set article structured data
   */
  setArticle(data) {
    const {
      headline,
      description,
      image,
      datePublished,
      dateModified,
      author,
      url
    } = data

    const article = {
      '@context': 'https://schema.org',
      '@type': 'Article',
      headline,
      description,
      image: Array.isArray(image) ? image : [image],
      datePublished,
      dateModified,
      author: {
        '@type': 'Person',
        name: author
      },
      url
    }

    this.setStructuredData(article)
    return this
  }

  /**
   * Internal: update or create meta tag
   */
  _updateMeta(name, content) {
    let meta = document.querySelector(`meta[name="${name}"], meta[property="${name}"]`)

    if (!meta) {
      meta = document.createElement('meta')
      const isProperty = name.includes(':')
      if (isProperty) {
        meta.setAttribute('property', name)
      } else {
        meta.setAttribute('name', name)
      }
      document.head.appendChild(meta)
    }

    meta.content = content
  }

  /**
   * Generate share URL for social platforms
   */
  generateShareUrl(platform, options = {}) {
    const {
      text = this.current.title || '',
      url = this.current.canonical || window.location.href,
      hashtags = [],
      via = 'EliteUI'
    } = options

    const encoded = {
      text: encodeURIComponent(text),
      url: encodeURIComponent(url),
      hashtags: encodeURIComponent(hashtags.join(','))
    }

    const urls = {
      twitter: `https://twitter.com/intent/tweet?text=${encoded.text}&url=${encoded.url}&hashtags=${encoded.hashtags}&via=${via}`,
      facebook: `https://www.facebook.com/sharer/sharer.php?u=${encoded.url}`,
      linkedin: `https://www.linkedin.com/sharing/share-offsite/?url=${encoded.url}`,
      whatsapp: `https://wa.me/?text=${encoded.text}%20${encoded.url}`,
      telegram: `https://t.me/share/url?url=${encoded.url}&text=${encoded.text}`,
      email: `mailto:?subject=${encoded.text}&body=${encoded.url}`
    }

    return urls[platform.toLowerCase()] || null
  }

  /**
   * Copy share link to clipboard
   */
  async copyShareLink(platform) {
    const url = this.generateShareUrl(platform)
    if (!url) return false

    try {
      await navigator.clipboard.writeText(url)
      return true
    } catch (error) {
      console.error('[MetaManager] copy error:', error)
      return false
    }
  }

  /**
   * Get current meta state
   */
  getState() {
    return { ...this.current }
  }

  /**
   * Reset to defaults
   */
  reset() {
    this.current = { ...this.defaults }
    if (this.defaults.title) {
      document.title = this.defaults.title
    }
    return this
  }

  /**
   * Debug: print current meta state
   */
  debug() {
    console.group('[MetaManager]')
    console.log('Current state:', this.current)
    console.log('Document title:', document.title)
    console.log('Meta tags:', {
      description: document.querySelector('meta[name="description"]')?.content,
      og_title: document.querySelector('meta[property="og:title"]')?.content,
      og_image: document.querySelector('meta[property="og:image"]')?.content,
      canonical: document.querySelector('link[rel="canonical"]')?.href
    })
    console.groupEnd()
  }
}

window.MetaManager = MetaManager

/**
 * SimpleStore
 * Global state management (similar a Zustand, pero sin dependencias)
 *
 * Propiedades:
 * - getState() / setState()
 * - subscribe(path, callback) - subscribe a cambios en path específico
 * - computed: valores derivados del estado
 * - persistencia: localStorage/sessionStorage
 *
 * Uso:
 * const store = new SimpleStore({ count: 0 })
 * store.subscribe('count', (newVal, prevVal) => console.log(newVal))
 * store.setState({ count: 1 })
 */

class SimpleStore {
  constructor(initialState = {}, options = {}) {
    this._state = initialState
    this._subscribers = new Map() // path -> [callbacks]
    this._pathSubscribers = new Map() // deep path (dot notation) -> callback
    this._computed = new Map()
    this._computedCache = new Map()
    this._history = []
    this._redoHistory = []
    this._maxHistory = options.maxHistory || 50
    this._persistKey = options.persistKey || null

    // Restaurar del storage si está configurado
    if (this._persistKey) {
      this._restore()
    }

    // Devtools support (si existe window.__EXONOOR_DEVTOOLS__)
    if (typeof window !== 'undefined' && window.__EXONOOR_DEVTOOLS__) {
      window.__EXONOOR_DEVTOOLS__.registerStore(this)
    }
  }

  /**
   * Get state (snapshot)
   */
  getState() {
    return JSON.parse(JSON.stringify(this._state))
  }

  /**
   * Get value by path (dot notation)
   * getValue('user.profile.name')
   */
  getValue(path) {
    return this._getValueByPath(this._state, path)
  }

  _getValueByPath(obj, path) {
    if (!path) return obj
    return path.split('.').reduce((o, p) => o?.[p], obj)
  }

  /**
   * Set state (merge)
   */
  setState(updates) {
    if (typeof updates === 'function') {
      updates = updates(this._state)
    }

    const prevState = this._state
    const prevStateClone = JSON.parse(JSON.stringify(prevState))

    // Detectar cambios antes de actualizar
    const changes = {}
    for (const key in updates) {
      if (this._state[key] !== updates[key]) {
        changes[key] = true
      }
    }

    if (Object.keys(changes).length === 0) return // No-op

    // Clear redo history when making a new change
    this._redoHistory = []

    // Actualizar estado
    this._state = { ...this._state, ...updates }

    // Guardar en history
    this._history.push({
      timestamp: Date.now(),
      prevState: prevStateClone,
      newState: JSON.parse(JSON.stringify(this._state))
    })
    if (this._history.length > this._maxHistory) {
      this._history.shift()
    }

    // Notificar subscribers
    this._notify(prevState, this._state, Object.keys(changes))

    // Persistir si está configurado
    if (this._persistKey) {
      this._persist()
    }
  }

  /**
   * Subscribe a cambios de un path
   * Soporta keys top-level y paths profundos con dot notation
   * @param {string} path - 'user.name' para deep paths, 'key' para top-level, '*' para todos
   * @param {Function} callback
   * @returns {Function} unsubscribe
   */
  subscribe(path = '*', callback) {
    // Deep path subscriber (dot notation like 'user.name')
    if (path !== '*' && path.includes('.')) {
      if (!this._pathSubscribers.has(path)) {
        this._pathSubscribers.set(path, [])
      }
      this._pathSubscribers.get(path).push(callback)

      return () => {
        const callbacks = this._pathSubscribers.get(path)
        this._pathSubscribers.set(path, callbacks.filter(cb => cb !== callback))
      }
    }

    // Top-level key or global subscriber
    if (!this._subscribers.has(path)) {
      this._subscribers.set(path, [])
    }

    this._subscribers.get(path).push(callback)

    // Retornar función de unsubscribe
    return () => {
      const callbacks = this._subscribers.get(path)
      this._subscribers.set(path, callbacks.filter(cb => cb !== callback))
    }
  }

  _notify(prevState, currState, changedKeys) {
    // Notificar subscribers específicos
    for (const key of changedKeys) {
      const callbacks = this._subscribers.get(key) || []
      const prevVal = this._getValueByPath(prevState, key)
      const currVal = this._getValueByPath(currState, key)

      callbacks.forEach(cb => {
        try {
          cb(currVal, prevVal, key)
        } catch (e) {
          console.error('[SimpleStore] subscriber error:', e)
        }
      })
    }

    // Notificar subscribers globales
    const globalCallbacks = this._subscribers.get('*') || []
    globalCallbacks.forEach(cb => {
      try {
        cb(currState, prevState)
      } catch (e) {
        console.error('[SimpleStore] subscriber error:', e)
      }
    })

    // Notificar deep path subscribers (dot notation like 'user.name')
    this._pathSubscribers.forEach((callbacks, path) => {
      const prevVal = this._getValueByPath(prevState, path)
      const currVal = this._getValueByPath(currState, path)

      // Only notify if the value at this path actually changed
      if (prevVal !== currVal) {
        callbacks.forEach(cb => {
          try {
            cb(currVal, prevVal, path)
          } catch (e) {
            console.error('[SimpleStore] subscriber error:', e)
          }
        })
      }
    })

    // Invalidar computed cache
    this._computedCache.clear()
  }

  /**
   * Definir valor computado
   * @param {string} key
   * @param {Function} computeFn - (state) => value
   */
  defineComputed(key, computeFn) {
    this._computed.set(key, computeFn)
    // Evaluar una vez para cachear
    this._computedCache.set(key, computeFn(this._state))
  }

  /**
   * Get computed value
   */
  getComputed(key) {
    if (!this._computed.has(key)) {
      return undefined
    }

    if (this._computedCache.has(key)) {
      return this._computedCache.get(key)
    }

    const computeFn = this._computed.get(key)
    const value = computeFn(this._state)
    this._computedCache.set(key, value)
    return value
  }

  /**
   * Batch updates (solo notifica una vez al final)
   */
  batch(updatesFn) {
    const prevState = this._state

    // Acumular cambios sin notificar
    const updates = {}
    const tempSetState = (u) => {
      Object.assign(updates, typeof u === 'function' ? u(this._state) : u)
    }

    // Llamar callback con setState temporal
    updatesFn(tempSetState)

    // Ahora actualizar de verdad
    if (Object.keys(updates).length > 0) {
      this._state = { ...this._state, ...updates }
      this._notify(prevState, this._state, Object.keys(updates))

      if (this._persistKey) {
        this._persist()
      }
    }
  }

  /**
   * Undo to previous state
   * Pushes current state onto redo history
   */
  undo() {
    if (this._history.length > 0) {
      const entry = this._history.pop()
      // Save current state for redo
      this._redoHistory.push({
        prevState: entry.prevState,
        newState: entry.newState
      })
      this._state = entry.prevState
      this._notify(entry.newState, this._state, Object.keys(entry.prevState))
    }
  }

  /**
   * Redo to next state
   * Pops from redo history and restores the state
   */
  redo() {
    if (this._redoHistory.length > 0) {
      const entry = this._redoHistory.pop()
      // Save previous state back onto history for undo
      this._history.push({
        prevState: entry.prevState,
        newState: entry.newState
      })
      this._state = entry.newState
      this._notify(entry.prevState, this._state, Object.keys(entry.newState))
    }
  }

  /**
   * Get history
   */
  getHistory() {
    return [...this._history]
  }

  /**
   * Persistencia
   */
  _persist() {
    try {
      if (typeof window === 'undefined') return
      const storage = window.localStorage || window.sessionStorage
      storage.setItem(this._persistKey, JSON.stringify(this._state))
    } catch (e) {
      console.warn('[SimpleStore] persist failed:', e)
    }
  }

  _restore() {
    try {
      if (typeof window === 'undefined') return
      const storage = window.localStorage || window.sessionStorage
      const saved = storage.getItem(this._persistKey)
      if (saved) {
        this._state = JSON.parse(saved)
      }
    } catch (e) {
      console.warn('[SimpleStore] restore failed:', e)
    }
  }

  /**
   * Clear storage
   */
  clearPersistence() {
    if (typeof window === 'undefined') return
    const storage = window.localStorage || window.sessionStorage
    storage.removeItem(this._persistKey)
  }

  /**
   * Reset a estado inicial
   */
  reset(initialState) {
    this._state = initialState
    this._computedCache.clear()
    this._notify({}, this._state, Object.keys(initialState))
  }

  /**
   * Debug: imprimir estado actual
   */
  debug() {
    console.group(`[SimpleStore] State`)
    console.table(this._state)
    console.groupEnd()
  }
}

window.SimpleStore = SimpleStore

/**
 * Store Factory
 * Crea stores que se auto-registran con LazyLoader
 * 
 * Uso:
 * 
 * // Crear store
 * const cartStore = createStore('cartStore', {
 *   items: [],
 *   total: 0
 * })
 * 
 * // Usar en componente
 * class CartButton extends SimpleComponent {
 *   static dependencies = ['cartStore']
 *   
 *   constructor(selector, props) {
 *     super(selector, props)
 *     this.store = $lazy.get('cartStore')
 *   }
 * }
 */

function createStore(name, initialState = {}, options = {}) {
    const store = new SimpleStore(initialState, options)
    
    // Auto-registrar con LazyLoader
    if (window.LazyLoader) {
        LazyLoader.provide(name, store)
    }
    
    return store
}

/**
 * Registrar stores globales
 * Se llama desde stores/index.js
 */
function registerStores(registry) {
    for (const [name, config] of Object.entries(registry)) {
        if (config === false) continue
        
        const initialState = config.initialState || {}
        const options = config.options || {}
        
        const store = createStore(name, initialState, options)
        
        // Llamar init si existe
        if (config.init) {
            config.init(store)
        }
    }
}

// Exports
window.createStore = createStore
window.registerStores = registerStores

/**
 * Context
 * Compartir estado entre componentes sin prop drilling
 *
 * Uso:
 * const UserContext = new Context({ user: null })
 * userContext.subscribe(callback)
 * userContext.provide({ user: { id: 1, name: 'Juan' } })
 */

class Context {
  constructor(initialValue = {}) {
    this._value = initialValue
    this._subscribers = []
    this._providers = []
    this._watchers = new Map()

    // Dev tools
    this._debugName = 'Context'
    this._history = []
  }

  /**
   * Set debug name
   */
  setName(name) {
    this._debugName = name
    return this
  }

  /**
   * Get value
   */
  getValue() {
    return { ...this._value }
  }

  /**
   * Provide value (update)
   */
  provide(value) {
    const prevValue = this._value
    this._value = { ...this._value, ...value }

    // History
    this._history.push({
      timestamp: Date.now(),
      prevValue,
      newValue: this._value
    })
    if (this._history.length > 100) this._history.shift()

    // Notify
    this._notify(prevValue, this._value)
  }

  /**
   * Subscribe a cambios
   * @returns {Function} unsubscribe
   */
  subscribe(callback) {
    this._subscribers.push(callback)
    return () => {
      this._subscribers = this._subscribers.filter(cb => cb !== callback)
    }
  }

  /**
   * Watch específico
   * @param {string|Array} keys - 'user' o ['user', 'auth']
   * @param {Function} callback
   * @returns {Function} unwatch
   */
  watch(keys, callback) {
    const keyList = Array.isArray(keys) ? keys : [keys]
    const key = keyList.join('|')

    if (!this._watchers.has(key)) {
      this._watchers.set(key, [])
    }

    this._watchers.get(key).push({ keyList, callback })

    return () => {
      const watchers = this._watchers.get(key)
      this._watchers.set(key, watchers.filter(w => w.callback !== callback))
    }
  }

  _notify(prevValue, currValue) {
    // Global subscribers
    this._subscribers.forEach(cb => {
      try {
        cb(currValue, prevValue)
      } catch (e) {
        console.error(`[${this._debugName}] subscriber error:`, e)
      }
    })

    // Specific watchers
    for (const [key, watchers] of this._watchers.entries()) {
      watchers.forEach(({ keyList, callback }) => {
        const prevVals = keyList.map(k => prevValue?.[k])
        const currVals = keyList.map(k => currValue?.[k])

        const hasChanged = prevVals.some((v, i) => v !== currVals[i])

        if (hasChanged) {
          try {
            callback(...currVals, ...prevVals)
          } catch (e) {
            console.error(`[${this._debugName}] watcher error:`, e)
          }
        }
      })
    }
  }

  /**
   * Use context in component
   * Convenience method para obtener valor + unsubscribe
   */
  use(callback) {
    callback(this._value)
    return this.subscribe(callback)
  }

  /**
   * Provider (para HTML atributos)
   */
  createProvider(value = {}) {
    const provider = {
      value: { ...this._value, ...value },
      children: []
    }
    this._providers.push(provider)
    this.provide(provider.value)
    return provider
  }

  /**
   * Consumer helpers
   */
  connect(component) {
    if (typeof component === 'function') {
      // Function component
      return this.subscribe((value) => {
        component(value)
      })
    } else if (component?.setState) {
      // Class component con setState
      return this.subscribe((value) => {
        component.setState({ ...value })
      })
    }
  }

  /**
   * Reset a valor inicial
   */
  reset(initialValue) {
    this._value = initialValue
    this._notify({}, this._value)
  }

  /**
   * Get history
   */
  getHistory() {
    return [...this._history]
  }

  /**
   * Debug
   */
  debug() {
    console.group(`[${this._debugName}]`)
    console.log('Current value:', this._value)
    console.log('Subscribers:', this._subscribers.length)
    console.log('Watchers:', this._watchers.size)
    console.log('History:', this._history.length)
    console.groupEnd()
  }
}

// Composite Context para múltiples contextos
class ContextProvider {
  constructor(contexts = {}) {
    this._contexts = contexts
  }

  addContext(name, context) {
    this._contexts[name] = context
    return this
  }

  getContext(name) {
    return this._contexts[name]
  }

  getAllContexts() {
    return { ...this._contexts }
  }

  debug() {
    console.group('[ContextProvider]')
    for (const [name, ctx] of Object.entries(this._contexts)) {
      console.log(`${name}:`)
      ctx.debug()
    }
    console.groupEnd()
  }
}

window.Context = Context
window.ContextProvider = ContextProvider

/**
 * ErrorBoundary
 * Captura errores de componentes y maneja fallbacks
 *
 * Uso:
 * const boundary = new ErrorBoundary(fallbackUI)
 * boundary.catch(component)
 */

class ErrorBoundary {
  constructor(fallbackUI = null) {
    this._fallbackUI = fallbackUI
    this._errors = []
    this._errorHandlers = []
    this._recoveryHandlers = []
  }

  /**
   * Ejecutar componente con error handling
   * @param {Function|Promise} fn
   * @param {string} context
   */
  async catch(fn, context = 'unknown') {
    try {
      if (typeof fn === 'function') {
        const result = fn()
        if (result instanceof Promise) {
          return await result
        }
        return result
      } else {
        return await fn
      }
    } catch (error) {
      this._handleError(error, context)
      return this._getFallback()
    }
  }

  /**
   * Register error handler
   */
  onError(handler) {
    this._errorHandlers.push(handler)
    return () => {
      this._errorHandlers = this._errorHandlers.filter(h => h !== handler)
    }
  }

  /**
   * Register recovery handler
   */
  onRecover(handler) {
    this._recoveryHandlers.push(handler)
    return () => {
      this._recoveryHandlers = this._recoveryHandlers.filter(h => h !== handler)
    }
  }

  _handleError(error, context) {
    const errorEntry = {
      timestamp: Date.now(),
      message: error.message,
      stack: error.stack,
      context,
      error
    }

    this._errors.push(errorEntry)

    // Keep only last 50 errors
    if (this._errors.length > 50) {
      this._errors.shift()
    }

    // Call handlers
    this._errorHandlers.forEach(handler => {
      try {
        handler(error, context)
      } catch (e) {
        console.error('[ErrorBoundary] handler error:', e)
      }
    })

    // Log error
    console.error(`[ErrorBoundary] ${context}:`, error)
  }

  _getFallback() {
    if (this._fallbackUI) {
      if (typeof this._fallbackUI === 'function') {
        return this._fallbackUI(this._errors[this._errors.length - 1])
      }
      return this._fallbackUI
    }

    return {
      ok: false,
      error: this._errors[this._errors.length - 1]?.message || 'Unknown error'
    }
  }

  /**
   * Recover from error
   */
  recover() {
    if (this._errors.length === 0) return

    this._errors.pop()

    this._recoveryHandlers.forEach(handler => {
      try {
        handler()
      } catch (e) {
        console.error('[ErrorBoundary] recovery handler error:', e)
      }
    })
  }

  /**
   * Get errors
   */
  getErrors() {
    return [...this._errors]
  }

  /**
   * Clear errors
   */
  clearErrors() {
    this._errors = []
  }

  /**
   * Debug
   */
  debug() {
    console.group('[ErrorBoundary]')
    console.log('Total errors:', this._errors.length)
    console.table(this._errors.map(e => ({
      context: e.context,
      message: e.message,
      time: new Date(e.timestamp).toLocaleTimeString()
    })))
    console.groupEnd()
  }
}

// Global error boundary (para eventos no capturados)
class GlobalErrorBoundary {
  constructor() {
    this._handlers = []
    this._setup()
  }

  _setup() {
    window.addEventListener('error', (event) => {
      this._handleError(event.error, 'uncaughtError')
    })

    window.addEventListener('unhandledrejection', (event) => {
      this._handleError(event.reason, 'unhandledPromiseRejection')
    })
  }

  onError(handler) {
    this._handlers.push(handler)
    return () => {
      this._handlers = this._handlers.filter(h => h !== handler)
    }
  }

  _handleError(error, type) {
    this._handlers.forEach(handler => {
      try {
        handler(error, type)
      } catch (e) {
        console.error('[GlobalErrorBoundary] handler error:', e)
      }
    })
  }
}

window.ErrorBoundary = ErrorBoundary
window.GlobalErrorBoundary = new GlobalErrorBoundary()

/**
 * Router
 * Enrutamiento cliente con layouts, nested routes, guards y lazy loading
 * 
 * Usage:
 * const router = new EliteRouter({
 *   useHash: true,
 *   layout: 'default-layout',
 *   routes: [...]
 * })
 * 
 * Routes:
 * {
 *   path: '/admin',
 *   component: 'AdminPage',
 *   lazy: { src: 'components/AdminPage.js' },  // Lazy loading
 *   layout: 'admin-layout',
 *   guards: ['isAuthenticated'],
 *   meta: { title: 'Admin' },
 *   children: [
 *     { path: 'users', component: 'UsersPage' },
 *     { path: 'settings', component: 'SettingsPage' }
 *   ]
 * }
 */

class EliteRouter {
    constructor(options = {}) {
        this._routes = []
        this._routeMap = new Map()
        this._subscribers = []
        this._currentRoute = null
        this._currentLayout = null
        this._layoutEl = null
        
        this._useHash = options.useHash !== false
        this._basePath = options.basePath || ''
        this._defaultLayout = options.layout || null
        this._layouts = new Map()
        
        // Global guards
        this._guards = []
        this._middleware = []
        
        // LazyLoader for dynamic imports
        this._lazyLoader = new LazyLoader()
        
        // ErrorBoundary
        this._errorBoundary = new ErrorBoundary({
            ok: false,
            error: 'Component failed to load'
        })
        
        // 404 handler
        this._notFoundHandler = null
        
        // Current instance for cleanup
        this._currentInstance = null
        
        this._setup()
    }

    _setup() {
        window.addEventListener('hashchange', () => this._handleRouteChange())
        window.addEventListener('popstate', () => this._handleRouteChange())
        window.$router = this
        this._handleRouteChange()
    }

    /**
     * Register layout component
     */
    registerLayout(name, layoutEl) {
        this._layouts.set(name, layoutEl)
    }

    /**
     * Add route
     */
    addRoute(route) {
        this._routes.push(route)
        this._buildRouteMap()
        return this
    }

    /**
     * Add multiple routes
     */
    addRoutes(routes) {
        this._routes.push(...routes)
        this._buildRouteMap()
        return this
    }

    /**
     * Build route map for fast lookup
     */
    _buildRouteMap() {
        this._routeMap.clear()
        
        const addToMap = (route, parent = null) => {
            const fullPath = parent 
                ? `${parent.path}${route.path}` 
                : route.path
            
            this._routeMap.set(fullPath, {
                ...route,
                fullPath,
                parent
            })
            
            // Add children
            if (route.children) {
                route.children.forEach(child => addToMap(child, route))
            }
        }
        
        this._routes.forEach(route => addToMap(route))
    }

    /**
     * Set 404 handler
     */
    setNotFound(handler) {
        this._notFoundHandler = handler
    }

    /**
     * Navigate to path
     */
    async navigate(path, state = {}) {
        if (!this._isSafePath(path)) {
            console.warn('[Router] blocked unsafe path:', path)
            return false
        }

        // Run global guards
        for (const guard of this._guards) {
            const result = await guard(path, this._currentRoute?.fullPath, state)
            if (result === false) return false
            if (result !== true && typeof result === 'string') {
                path = result // Allow guard to redirect
            }
        }

        if (this._useHash) {
            window.location.hash = path
        } else {
            window.history.pushState(state, '', path)
            this._handleRouteChange()
        }
        return true
    }

    /**
     * Check if path is safe
     */
    _isSafePath(path) {
        if (!path || typeof path !== 'string') return false
        const dangerous = ['javascript:', 'data:', 'vbscript:', 'file:']
        return !dangerous.some(p => path.toLowerCase().includes(p))
    }

    /**
     * Get current path
     */
    _getCurrentPath() {
        if (this._useHash) {
            const hash = window.location.hash.slice(1)
            return hash.startsWith('/') ? hash : '/' + hash
        }
        return window.location.pathname
    }

    /**
     * Handle route change
     */
    async _handleRouteChange() {
        const path = this._getCurrentPath()
        const routeInfo = this._matchRoute(path)
        
        if (!routeInfo) {
            this._currentRoute = { path, notFound: true }
            this._notify(this._currentRoute)
            this._notFoundHandler?.()
            return
        }

        const { route, params, parentRoute } = routeInfo

        // Run route-specific guards
        if (route.guards) {
            for (const guardName of route.guards) {
                const guardFn = this._getGuard(guardName)
                if (guardFn) {
                    const result = await guardFn(path, this._currentRoute?.fullPath, params)
                    if (result === false) {
                        console.log(`[Router] route guard "${guardName}" blocked`)
                        return
                    }
                }
            }
        }

        // Run middleware
        for (const mw of this._middleware) {
            await mw(path, params, route.meta)
        }

        // Update layout
        const layoutName = route.layout || parentRoute?.layout || this._defaultLayout
        await this._updateLayout(layoutName)

        // Update route
        this._currentRoute = {
            ...route,
            params,
            query: this._getQueryParams()
        }

        // Mount component if exists
        if (route.component) {
            await this._mountComponent(route)
        }

        // Notify subscribers
        this._notify(this._currentRoute)
    }

    /**
     * Get guard function by name
     */
    _getGuard(name) {
        // Built-in guards
        if (name === 'isAuthenticated') {
            return () => {
                if (!$permissions?.getCurrentUser()) {
                    this.navigate('/login')
                    return false
                }
                return true
            }
        }
        if (name === 'isGuest') {
            return () => {
                if ($permissions?.getCurrentUser()) {
                    this.navigate('/')
                    return false
                }
                return true
            }
        }
        if (name === 'isAdmin') {
            return () => {
                if (!$permissions?.isRole('admin')) {
                    this.navigate('/')
                    return false
                }
                return true
            }
        }
        
        // Custom guard from window
        if (typeof window[name] === 'function') {
            return window[name]
        }
        
        return null
    }

    /**
     * Mount component to container
     */
    async _mountComponent(route) {
        const container = route.container || '#app'
        const el = document.querySelector(container)
        if (!el) {
            console.warn(`[Router] container not found: ${container}`)
            return
        }

        let ComponentClass = window[route.component]
        
        // Lazy loading
        if (!ComponentClass && route.lazy) {
            const src = route.lazy.src || `components/${route.component}.js`
            try {
                await this._lazyLoader.loadScript(src, route.component)
                ComponentClass = window[route.component]
            } catch (e) {
                console.error(`[Router] failed to lazy load ${route.component}:`, e)
                this._errorBoundary._handleError(e, `lazy:${route.component}`)
                return
            }
        }

        if (!ComponentClass) {
            console.warn(`[Router] component not found: ${route.component}`)
            return
        }

        // Pass params and query
        const props = { 
            ...route.params,
            ...(route.props || {}),
            query: this._getQueryParams()
        }

        // Cleanup previous instance
        if (this._currentInstance) {
            this._currentInstance.unmount?.()
        }

        // Mount with ErrorBoundary
        try {
            const instance = new ComponentClass(container, props)
            instance.mount()
            this._currentInstance = instance
        } catch (e) {
            console.error(`[Router] error mounting ${route.component}:`, e)
            this._errorBoundary._handleError(e, `mount:${route.component}`)
            // Show fallback
            el.innerHTML = `<div class="text-red-500 p-4">Error loading component: ${route.component}</div>`
        }
    }

    /**
     * Update layout
     */
    async _updateLayout(layoutName) {
        if (this._currentLayout === layoutName) return
        
        if (!layoutName) {
            this._layoutEl = null
            this._currentLayout = null
            return
        }

        const layoutEl = this._layouts.get(layoutName)
        if (!layoutEl) {
            // Try to find element with id
            const el = document.querySelector(`#${layoutName}`)
            if (el) {
                this._layoutEl = el
                this._currentLayout = layoutName
            }
            return
        }

        this._layoutEl = layoutEl
        this._currentLayout = layoutName
    }

    /**
     * Match route to path
     */
    _matchRoute(path) {
        // Clean path
        path = path.split('?')[0]
        
        // Check exact match first
        const exact = this._routeMap.get(path)
        if (exact) return { route: exact, params: {}, parentRoute: exact.parent }

        // Check with trailing slash
        if (path.endsWith('/') && path !== '/') {
            const withoutSlash = path.slice(0, -1)
            const match = this._routeMap.get(withoutSlash)
            if (match) return { route: match, params: {}, parentRoute: match.parent }
        }

        // Check dynamic routes
        for (const [routePath, routeInfo] of this._routeMap) {
            const params = this._matchDynamicRoute(routePath, path)
            if (params) {
                return { 
                    route: routeInfo, 
                    params, 
                    parentRoute: routeInfo.parent 
                }
            }
        }

        return null
    }

    /**
     * Match dynamic route
     */
    _matchDynamicRoute(pattern, path) {
        const patternParts = pattern.split('/').filter(Boolean)
        const pathParts = path.split('/').filter(Boolean)

        if (patternParts.length !== pathParts.length) return null

        const params = {}
        for (let i = 0; i < patternParts.length; i++) {
            const p = patternParts[i]
            const a = pathParts[i]

            if (p.startsWith(':')) {
                params[p.slice(1)] = this._sanitizeParam(a)
            } else if (p !== a) {
                return null
            }
        }

        return params
    }

    /**
     * Sanitize route param
     */
    _sanitizeParam(value) {
        try {
            const el = document.createElement('div')
            el.textContent = decodeURIComponent(value)
            return el.innerHTML
        } catch {
            return value
        }
    }

    /**
     * Get query params
     */
    _getQueryParams() {
        const search = this._useHash
            ? window.location.hash.split('?')[1] || ''
            : window.location.search.slice(1)
        
        if (!search) return {}
        
        const params = {}
        search.split('&').slice(0, 50).forEach(pair => {
            const [key, value = ''] = pair.split('=')
            if (key) {
                params[decodeURIComponent(key)] = decodeURIComponent(value.slice(0, 2000))
            }
        })
        return params
    }

    /**
     * Subscribe to route changes
     */
    subscribe(callback) {
        this._subscribers.push(callback)
        return () => {
            this._subscribers = this._subscribers.filter(cb => cb !== callback)
        }
    }

    _notify(route) {
        this._subscribers.forEach(cb => cb(route))
    }

    /**
     * Add global guard
     */
    beforeEach(guard) {
        this._guards.push(guard)
        return () => {
            this._guards = this._guards.filter(g => g !== guard)
        }
    }

    /**
     * Add middleware
     */
    use(middleware) {
        this._middleware.push(middleware)
        return () => {
            this._middleware = this._middleware.filter(m => m !== middleware)
        }
    }

    /**
     * Get current route
     */
    getCurrentRoute() {
        return this._currentRoute
    }

    /**
     * Back
     */
    back() {
        window.history.back()
    }

    /**
     * Forward
     */
    forward() {
        window.history.forward()
    }
}

window.EliteRouter = EliteRouter

/**
 * LazyLoader
 * 
 * Sistema de carga perezosa con resolución de dependencias.
 * Funciona con file:// protocolo (sin CORS).
 * 
 * Uso:
 * 
 * // Registrar módulo/dependencia
 * LazyLoader.provide('cartStore', cartStoreInstance)
 * LazyLoader.provide('userStore', userStoreInstance)
 * 
 * // Declarar dependencias en componente
 * class CartButton extends SimpleComponent {
 *   static dependencies = ['cartStore'] // se cargará antes
 * }
 * 
 * // Cargar componente lazily
 * await LazyLoader.loadComponent('CartButton', '#container')
 * 
 * // Cargar página con sus componentes
 * await LazyLoader.loadPage('HomePage', '#app')
 */

class LazyLoader {
    constructor() {
        this._providers = new Map()
        this._loaded = new Map()
        this._loading = new Map()
        this._callbacks = new Map()
    }

    /**
     * Registrar un módulo/dependencia global
     */
    provide(name, instance) {
        this._providers.set(name, instance)
        this._loaded.set(name, true)
        
        // Notificar a los等待者
        if (this._callbacks.has(name)) {
            this._callbacks.get(name).forEach(cb => cb(instance))
            this._callbacks.delete(name)
        }
    }

    /**
     * Obtener módulo/dependencia
     */
    get(name) {
        return this._providers.get(name)
    }

    /**
     * Verificar si está disponible
     */
    has(name) {
        return this._providers.has(name)
    }

    /**
     * Esperar a que un módulo esté disponible
     */
    when(name) {
        if (this._providers.has(name)) {
            return Promise.resolve(this._providers.get(name))
        }
        
        return new Promise(resolve => {
            if (!this._callbacks.has(name)) {
                this._callbacks.set(name, [])
            }
            this._callbacks.get(name).push(resolve)
        })
    }

    /**
     * Cargar script dinámicamente (sin ES modules para file://)
     */
    async _loadScript(src) {
        return new Promise((resolve, reject) => {
            // Verificar si ya está cargado
            const existing = document.querySelector(`script[src="${src}"]`)
            if (existing) {
                resolve()
                return
            }

            const script = document.createElement('script')
            script.src = src
            script.async = false // mantener orden
            script.onload = () => resolve()
            script.onerror = (e) => {
                console.warn(`[LazyLoader] Failed to load: ${src}`)
                resolve() // No fallar, permitir continuar
            }
            document.head.appendChild(script)
        })
    }

    /**
     * Cargar módulo y sus dependencias
     */
    async loadModule(name, basePath = 'modules') {
        if (this._loaded.has(name)) return this.get(name)
        if (this._loading.has(name)) {
            return this.when(name)
        }

        this._loading.set(name, true)

        const path = `${basePath}/${name}/${name}.js`
        
        try {
            await this._loadScript(path)
            
            // Después de cargar, obtener la instancia del provider
            const instance = this._providers.get(name)
            if (!instance) {
                console.warn(`[LazyLoader] Module ${name} loaded but no provider registered`)
            }
            
            this._loaded.set(name, true)
            this._loading.delete(name)
            
            return instance
        } catch (e) {
            this._loading.delete(name)
            throw e
        }
    }

    /**
     * Cargar store
     */
    async loadStore(name) {
        return this.loadModule(name, 'stores')
    }

    /**
     * Cargar componente con sus dependencias
     */
    async loadComponent(name, container, props = {}) {
        // 1. Cargar store dependencies si el componente las declara
        const ComponentClass = window[name]
        
        if (ComponentClass && ComponentClass.dependencies) {
            for (const dep of ComponentClass.dependencies) {
                if (!this.has(dep)) {
                    // Intentar cargar desde stores/
                    await this.loadStore(dep)
                }
            }
        }

        // 2. Cargar JS del componente si no está cargado
        if (!window[name]) {
            await this._loadScript(`components/${name}/${name}.js`)
        }

        // 3. Obtener la clase
        const Cls = window[name]
        if (!Cls) {
            throw new Error(`[LazyLoader] Component not found: ${name}`)
        }

        // 4. Crear instancia y montar
        const instance = new Cls(container, props)
        instance.mount()
        
        this._loaded.set(`component:${name}`, instance)
        return instance
    }

    /**
     * Cargar página con sus componentes
     */
    async loadPage(name, container, props = {}) {
        // 1. Cargar JS de la página
        if (!window[name]) {
            await this._loadScript(`pages/${name}/${name}.page.js`)
        }

        // 2. Obtener la clase
        const Cls = window[name]
        if (!Cls) {
            throw new Error(`[LazyLoader] Page not found: ${name}`)
        }

        // 3. Cargar dependencias de la página
        if (Cls.dependencies) {
            for (const dep of Cls.dependencies) {
                if (!this.has(dep)) {
                    await this.loadStore(dep)
                }
            }
        }

        // 4. Crear instancia y montar
        const instance = new Cls(container, props)
        instance.mount()
        
        this._loaded.set(`page:${name}`, instance)
        return instance
    }

    /**
     * Precargar módulo/componente sin instanciar
     */
    async preload(name, type = 'module', basePath = 'modules') {
        if (type === 'module') return this.loadModule(name, basePath)
        if (type === 'store') return this.loadStore(name)
        if (type === 'component') {
            if (!window[name]) {
                await this._loadScript(`components/${name}/${name}.js`)
            }
            return true
        }
        if (type === 'page') {
            if (!window[name]) {
                await this._loadScript(`pages/${name}/${name}.page.js`)
            }
            return true
        }
    }

    /**
     * Precargar varios módulos en paralelo
     */
    async preloadAll(items) {
        await Promise.all(items.map(({ name, type, path }) => 
            this.preload(name, type, path)
        ))
    }

    /**
     * Obtener instancia de componente/página ya cargada
     */
    getLoaded(name, type = 'component') {
        return this._loaded.get(`${type}:${name}`)
    }
}

// Instancia global
window.LazyLoader = new LazyLoader()
window.$lazy = window.LazyLoader // alias

console.log('[LazyLoader] Initialized')

/**
 * HttpClient
 * Wrapper centralizado para fetch con interceptors, auth, error handling
 *
 * Uso:
 * const http = new HttpClient({ baseUrl: '/api' })
 * const data = await http.get('/users')
 * await http.post('/users', { name: 'Juan' })
 */

class HttpClient {
  constructor(options = {}) {
    this.baseUrl = options.baseUrl || ''
    this.timeout = options.timeout || 30000
    this.headers = options.headers || {}

    this.requestInterceptors = []
    this.responseInterceptors = []
    this.errorInterceptors = []
  }

  /**
   * GET request
   */
  async get(url, options = {}) {
    return this.request(url, { ...options, method: 'GET' })
  }

  /**
   * POST request
   */
  async post(url, data = null, options = {}) {
    return this.request(url, {
      ...options,
      method: 'POST',
      body: data
    })
  }

  /**
   * PATCH request
   */
  async patch(url, data = null, options = {}) {
    return this.request(url, {
      ...options,
      method: 'PATCH',
      body: data
    })
  }

  /**
   * PUT request
   */
  async put(url, data = null, options = {}) {
    return this.request(url, {
      ...options,
      method: 'PUT',
      body: data
    })
  }

  /**
   * DELETE request
   */
  async delete(url, options = {}) {
    return this.request(url, { ...options, method: 'DELETE' })
  }

  /**
   * Main request method
   */
  async request(url, options = {}) {
    const fullUrl = this._buildUrl(url)
    const method = options.method || 'GET'
    const timeout = options.timeout || this.timeout

    try {
      // Build request
      let request = {
        method,
        headers: {
          'Content-Type': 'application/json',
          ...this.headers,
          ...options.headers
        },
        ...options
      }

      // Run request interceptors
      for (const interceptor of this.requestInterceptors) {
        try {
          request = await interceptor(request)
        } catch (e) {
          console.error('[HttpClient] request interceptor error:', e)
        }
      }

      // Add body if needed
      if (options.body && method !== 'GET' && method !== 'DELETE') {
        request.body = typeof options.body === 'string'
          ? options.body
          : JSON.stringify(options.body)
      }

      // Fetch with timeout
      const controller = new AbortController()
      const timeoutId = setTimeout(() => controller.abort(), timeout)

      const response = await fetch(fullUrl, {
        ...request,
        signal: controller.signal
      })

      clearTimeout(timeoutId)

      // Parse response
      const contentType = response.headers.get('content-type')
      let data = null

      if (contentType?.includes('application/json')) {
        data = await response.json()
      } else if (contentType?.includes('text')) {
        data = await response.text()
      } else {
        data = await response.blob()
      }

      // Build response object
      let responseObj = {
        ok: response.ok,
        status: response.status,
        statusText: response.statusText,
        data,
        headers: response.headers,
        _raw: response
      }

      // Run response interceptors
      for (const interceptor of this.responseInterceptors) {
        try {
          responseObj = await interceptor(responseObj)
        } catch (e) {
          console.error('[HttpClient] response interceptor error:', e)
        }
      }

      // Handle errors
      if (!response.ok) {
        const error = new HttpError(
          `HTTP ${response.status}: ${response.statusText}`,
          response.status,
          data,
          response
        )

        // Run error interceptors
        for (const interceptor of this.errorInterceptors) {
          try {
            await interceptor(error)
          } catch (e) {
            console.error('[HttpClient] error interceptor failed:', e)
          }
        }

        throw error
      }

      return responseObj
    } catch (error) {
      if (error instanceof HttpError) {
        throw error
      }

      // Timeout or network error
      if (error.name === 'AbortError') {
        throw new HttpError(
          `Request timeout (${timeout}ms)`,
          0,
          null,
          null
        )
      }

      throw new HttpError(
        error.message || 'Network request failed',
        0,
        null,
        null
      )
    }
  }

  /**
   * Add request interceptor
   */
  interceptRequest(handler) {
    this.requestInterceptors.push(handler)
    return () => {
      this.requestInterceptors = this.requestInterceptors.filter(h => h !== handler)
    }
  }

  /**
   * Add response interceptor
   */
  interceptResponse(handler) {
    this.responseInterceptors.push(handler)
    return () => {
      this.responseInterceptors = this.responseInterceptors.filter(h => h !== handler)
    }
  }

  /**
   * Add error interceptor
   */
  interceptError(handler) {
    this.errorInterceptors.push(handler)
    return () => {
      this.errorInterceptors = this.errorInterceptors.filter(h => h !== handler)
    }
  }

  /**
   * Set default headers
   */
  setHeaders(headers) {
    this.headers = { ...this.headers, ...headers }
  }

  /**
   * Set auth token
   */
  setAuthToken(token) {
    if (token) {
      this.setHeaders({ Authorization: `Bearer ${token}` })
    } else {
      const { Authorization, ...rest } = this.headers
      this.headers = rest
    }
  }

  /**
   * Build full URL
   */
  _buildUrl(path) {
    if (path.startsWith('http')) return path
    return this.baseUrl + (path.startsWith('/') ? path : '/' + path)
  }
}

/**
 * HttpError
 * Custom error for HTTP requests
 */
class HttpError extends Error {
  constructor(message, status, data, response) {
    super(message)
    this.name = 'HttpError'
    this.status = status
    this.data = data
    this.response = response
  }

  isClientError() {
    return this.status >= 400 && this.status < 500
  }

  isServerError() {
    return this.status >= 500
  }

  isNetworkError() {
    return this.status === 0
  }

  isTimeout() {
    return this.message.includes('timeout')
  }
}

window.HttpClient = HttpClient
window.HttpError = HttpError

/**
 * $http - Ultra simple HTTP client
 * Wrapper minimalista sobre fetch con API intuitiva
 * 
 * Uso:
 * 
 * // GET simple
 * const data = await $http('/users')
 * 
 * // POST con body
 * const user = await $http('/users', { name: 'Juan' })
 * 
 * // Con opciones
 * const data = await $http('/users', {
 *   method: 'POST',
 *   body: { name: 'Juan' },
 *   headers: { 'X-Custom': 'value' }
 * })
 * 
 * // Instancia personalizada
 * const api = $http.create({ baseUrl: '/api' })
 * await api('/users')
 */

class $HttpClient {
  constructor(options = {}) {
    this.baseUrl = options.baseUrl || ''
    this.timeout = options.timeout || 10000
    this.defaults = options.headers ? { headers: options.headers } : {}
  }

  async request(url, options = {}) {
    const config = {
      method: options.method || 'GET',
      headers: {
        'Content-Type': 'application/json',
        ...this.defaults.headers,
        ...options.headers
      },
      ...options
    }

    // Body handling
    if (config.body && typeof config.body === 'object' && config.method !== 'GET') {
      config.body = JSON.stringify(config.body)
    }

    // Build URL
    let fullUrl = url
    if (!url.startsWith('http')) {
      fullUrl = this.baseUrl + (url.startsWith('/') ? url : '/' + url)
    }

    // Timeout
    const controller = new AbortController()
    const timeoutId = setTimeout(() => controller.abort(), this.timeout)
    config.signal = controller.signal

    try {
      const res = await fetch(fullUrl, config)
      clearTimeout(timeoutId)

      // Parse response
      const contentType = res.headers.get('content-type')
      let data

      if (res.status === 204) {
        data = null
      } else if (contentType?.includes('application/json')) {
        data = await res.json()
      } else {
        data = await res.text()
      }

      if (!res.ok) {
        throw new $HttpError(`HTTP ${res.status}`, res.status, data)
      }

      return data

    } catch (e) {
      clearTimeout(timeoutId)
      
      if (e.name === 'AbortError') {
        throw new $HttpError(`Timeout (${this.timeout}ms)`, 0, null)
      }
      
      if (e instanceof $HttpError) throw e
      
      throw new $HttpError(e.message || 'Request failed', 0, null)
    }
  }

  get(url, options = {}) {
    return this.request(url, { ...options, method: 'GET' })
  }

  post(url, body, options = {}) {
    return this.request(url, { ...options, method: 'POST', body })
  }

  put(url, body, options = {}) {
    return this.request(url, { ...options, method: 'PUT', body })
  }

  patch(url, body, options = {}) {
    return this.request(url, { ...options, method: 'PATCH', body })
  }

  delete(url, options = {}) {
    return this.request(url, { ...options, method: 'DELETE' })
  }
}

class $HttpError extends Error {
  constructor(message, status, data) {
    super(message)
    this.name = '$HttpError'
    this.status = status
    this.data = data
  }
}

// Default instance
const $http = new $HttpClient()

// Create custom instance
$http.create = (options) => new $HttpClient(options)

// Export
window.$http = $http
window.$HttpClient = $HttpClient
window.$HttpError = $HttpError

console.log('[$http] Simple HTTP client ready')

/**
 * $debug - Debugging utilities con lifecycle tracking
 * 
 * Uso:
 * 
 * // Logging simple
 * $debug.log('User logged in', { userId: 123 })
 * $debug.warn('Rate limit approaching')
 * $debug.error('API failed', error)
 * 
 * // Lifecycle tracking
 * $debug.trackComponent('Hero', 'mount')
 * $debug.trackComponent('Hero', 'render')
 * $debug.trackComponent('Hero', 'unmount')
 * 
 * // Performance
 * $debug.time('api-request')
 * await $http('/users')
 * $debug.timeEnd('api-request')
 * 
 * // State snapshots
 * $debug.snapshot('state-before-login', store.getState())
 * 
 * // DevTools panel
 * $debug.panel() // Abre DevTools en el browser
 */

const $debug = {
  _enabled: true,
  _logs: [],
  _maxLogs: 100,
  _lifecycle: new Map(),
  _timers: new Map(),
  _listeners: [],

  // Enable/disable
  enable() { this._enabled = true },
  disable() { this._enabled = false },
  isEnabled() { return this._enabled },

  // Basic logging
  log(...args) {
    if (!this._enabled) return
    console.log(`[${timestamp()}]`, ...args)
    this._addLog('log', args)
  },

  warn(...args) {
    if (!this._enabled) return
    console.warn(`[${timestamp()}] ⚠️`, ...args)
    this._addLog('warn', args)
  },

  error(...args) {
    if (!this._enabled) return
    console.error(`[${timestamp()}] ❌`, ...args)
    this._addLog('error', args)
  },

  info(...args) {
    if (!this._enabled) return
    console.info(`[${timestamp()}] ℹ️`, ...args)
    this._addLog('info', args)
  },

  // Group logs
  group(name) {
    if (!this._enabled) return
    console.group(`[${timestamp()}] ${name}`)
  },
  groupEnd() {
    console.groupEnd()
  },

  // Lifecycle tracking
  trackComponent(name, event, data = {}) {
    if (!this._lifecycle.has(name)) {
      this._lifecycle.set(name, [])
    }

    const entry = {
      event,
      timestamp: Date.now(),
      data
    }

    this._lifecycle.get(name).push(entry)

    // Keep last 50 entries per component
    const entries = this._lifecycle.get(name)
    if (entries.length > 50) entries.shift()

    // Log if enabled
    if (this._enabled) {
      const icon = event === 'mount' ? '🚀' : event === 'unmount' ? '🛑' : event === 'error' ? '💥' : '📦'
      console.log(`[${timestamp()}] ${icon} ${name}:${event}`, data)
    }

    // Notify listeners
    this._notify('lifecycle', { name, event, data, timestamp: entry.timestamp })
  },

  // Get lifecycle history
  getLifecycle(name) {
    return name ? this._lifecycle.get(name) || [] : Object.fromEntries(this._lifecycle)
  },

  // Clear lifecycle for component
  clearLifecycle(name) {
    if (name) {
      this._lifecycle.delete(name)
    } else {
      this._lifecycle.clear()
    }
  },

  // Timer utilities
  time(label) {
    this._timers.set(label, Date.now())
  },

  timeEnd(label) {
    const start = this._timers.get(label)
    if (start) {
      const duration = Date.now() - start
      this._timers.delete(label)
      const msg = `${label}: ${duration}ms`
      if (duration > 1000) {
        this.warn(`⏱️ ${msg}`)
      } else {
        this.log(`⏱️ ${msg}`)
      }
      return duration
    }
    this.warn(`Timer '${label}' was not started`)
    return null
  },

  // State snapshots
  snapshot(label, state) {
    this._addLog('snapshot', { label, state, timestamp: Date.now() })
    if (this._enabled) {
      console.log(`[${timestamp()}] 📸 Snapshot: ${label}`, state)
    }
  },

  // Subscribe to events
  on(event, callback) {
    this._listeners.push({ event, callback })
    return () => {
      this._listeners = this._listeners.filter(l => l.event !== event || l.callback !== callback)
    }
  },

  // Get all logs
  getLogs() {
    return [...this._logs]
  },

  // Clear logs
  clearLogs() {
    this._logs = []
  },

  // Export logs
  exportLogs() {
    const logs = this.getLogs()
    const blob = new Blob([JSON.stringify(logs, null, 2)], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `eliteui-logs-${Date.now()}.json`
    a.click()
    URL.revokeObjectURL(url)
    this.log('Logs exported')
  },

  // DevTools panel (simple table view)
  panel() {
    if (!this._enabled) return

    console.log('\n╔══════════════════════════════════════════════════════════════╗')
    console.log('║                    EliteUI DevTools                            ║')
    console.log('╠══════════════════════════════════════════════════════════════╣')

    // Components
    console.log('║ COMPONENTS                                                    ║')
    for (const [name, entries] of this._lifecycle) {
      const last = entries[entries.length - 1]
      const total = entries.length
      console.log(`║   ${pad(name, 15)} │ ${pad(last?.event || 'none', 10)} │ ${total} events`)
    }

    console.log('╠══════════════════════════════════════════════════════════════╣')

    // Recent logs
    console.log('║ RECENT LOGS                                                   ║')
    const recent = this._logs.slice(-10)
    for (const log of recent) {
      const icon = log.type === 'error' ? '❌' : log.type === 'warn' ? '⚠️' : 'ℹ️'
      const msg = log.data.slice(0, 3).map(d => typeof d === 'object' ? JSON.stringify(d) : String(d)).join(' ')
      console.log(`║ ${icon} ${pad(msg.substring(0, 50), 50)}`)
    }

    console.log('╠══════════════════════════════════════════════════════════════╣')
    console.log('║ Commands: $debug.exportLogs() | $debug.clearLogs()           ║')
    console.log('╚══════════════════════════════════════════════════════════════╝\n')
  },

  // Internal
  _addLog(type, data) {
    this._logs.push({ type, data, timestamp: Date.now() })
    if (this._logs.length > this._maxLogs) {
      this._logs.shift()
    }
  },

  _notify(event, data) {
    for (const listener of this._listeners) {
      if (listener.event === event) {
        try {
          listener.callback(data)
        } catch (e) {
          console.error('[$debug] listener error:', e)
        }
      }
    }
  }
}

// Helper
function timestamp() {
  return new Date().toISOString().substring(11, 23)
}

function pad(str, len) {
  return String(str).padEnd(len).substring(0, len)
}

// Auto-detect dev mode
if (location.hostname === 'localhost' || location.hostname === '127.0.0.1' || location.search.includes('debug')) {
  $debug.enable()
  console.log('[$debug] Dev mode enabled')
} else {
  $debug.disable()
}

// Export
window.$debug = $debug

console.log('[$debug] Debug tools ready')

/**
 * Validators
 * Mini-Zod: Schema validation sin dependencias
 * Validadores de seguridad prebuilts
 *
 * Uso:
 * Validators.email('user@example.com')        // null (válido)
 * Validators.email('invalid')                  // 'Invalid email' (error)
 * Validators.password('Pass123!', { min: 12 }) // null o error
 *
 * En useForm:
 * email: {
 *   value: '',
 *   validate: [Validators.email]
 * }
 */

const Validators = {
  /**
   * Required field
   */
  required: (message = 'This field is required') => {
    return (value) => {
      if (!value || (typeof value === 'string' && !value.trim())) {
        return message
      }
      return null
    }
  },

  /**
   * Email validation
   */
  email: (value, message = 'Invalid email') => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    if (!value) return null
    return emailRegex.test(value) ? null : message
  },

  /**
   * URL validation
   */
  url: (value, message = 'Invalid URL') => {
    if (!value) return null
    try {
      new URL(value)
      return null
    } catch {
      return message
    }
  },

  /**
   * Phone validation (basic)
   */
  phone: (value, message = 'Invalid phone number') => {
    if (!value) return null
    const phoneRegex = /^[\d\s\-\+\(\)]{10,}$/
    return phoneRegex.test(value.replace(/\D/g, '')) ? null : message
  },

  /**
   * Credit card validation (Luhn algorithm)
   */
  creditCard: (value, message = 'Invalid credit card') => {
    if (!value) return null

    const cardNumber = value.replace(/\D/g, '')
    if (cardNumber.length < 13 || cardNumber.length > 19) {
      return message
    }

    // Luhn algorithm
    let sum = 0
    let isEven = false

    for (let i = cardNumber.length - 1; i >= 0; i--) {
      let digit = parseInt(cardNumber[i], 10)

      if (isEven) {
        digit *= 2
        if (digit > 9) {
          digit -= 9
        }
      }

      sum += digit
      isEven = !isEven
    }

    return sum % 10 === 0 ? null : message
  },

  /**
   * Password strength validation
   * Options: { min: 8, requireUppercase: true, requireNumbers: true, requireSpecial: true }
   */
  password: (value, options = {}) => {
    if (!value) return 'Password is required'

    const {
      min = 8,
      requireUppercase = true,
      requireNumbers = true,
      requireSpecial = true
    } = options

    const errors = []

    if (value.length < min) {
      errors.push(`At least ${min} characters`)
    }

    if (requireUppercase && !/[A-Z]/.test(value)) {
      errors.push('At least one uppercase letter')
    }

    if (requireNumbers && !/\d/.test(value)) {
      errors.push('At least one number')
    }

    if (requireSpecial && !/[!@#$%^&*]/.test(value)) {
      errors.push('At least one special character (!@#$%^&*)')
    }

    return errors.length ? errors.join(', ') : null
  },

  /**
   * Min length
   */
  minLength: (min, message = `Minimum ${min} characters`) => {
    return (value) => {
      if (!value) return null
      return value.length >= min ? null : message
    }
  },

  /**
   * Max length
   */
  maxLength: (max, message = `Maximum ${max} characters`) => {
    return (value) => {
      if (!value) return null
      return value.length <= max ? null : message
    }
  },

  /**
   * Pattern matching
   */
  pattern: (regex, message = 'Invalid format') => {
    return (value) => {
      if (!value) return null
      return regex.test(value) ? null : message
    }
  },

  /**
   * Custom validator function
   */
  custom: (validatorFn, message = 'Validation failed') => {
    return (value) => {
      try {
        return validatorFn(value) ? null : message
      } catch (e) {
        console.error('[Validators] custom error:', e)
        return message
      }
    }
  },

  /**
   * XSS detection - check for dangerous patterns
   */
  noXSS: (value, message = 'Invalid characters detected') => {
    if (!value) return null

    // Dangerous patterns
    const xssPatterns = [
      /<script/i,
      /javascript:/i,
      /on\w+\s*=/i, // onclick=, onerror=, etc
      /<iframe/i,
      /eval\(/i,
      /expression\(/i
    ]

    for (const pattern of xssPatterns) {
      if (pattern.test(value)) {
        return message
      }
    }

    return null
  },

  /**
   * SQL injection detection
   */
  noSQLi: (value, message = 'Invalid input detected') => {
    if (!value) return null

    const sqliPatterns = [
      /('|(--)|;|\/\*|\*\/|xp_|sp_)/i,
      /union.*select/i,
      /insert.*into/i,
      /delete.*from/i,
      /drop.*table/i,
      /update.*set/i
    ]

    for (const pattern of sqliPatterns) {
      if (pattern.test(value)) {
        return message
      }
    }

    return null
  },

  /**
   * Match another field (password confirmation, etc)
   */
  matches: (otherValue, message = 'Fields do not match') => {
    return (value) => {
      if (!value) return null
      return value === otherValue ? null : message
    }
  },

  /**
   * SSN format (XXX-XX-XXXX)
   */
  ssn: (value, message = 'Invalid SSN format') => {
    if (!value) return null
    const ssnRegex = /^\d{3}-\d{2}-\d{4}$/
    return ssnRegex.test(value) ? null : message
  },

  /**
   * Zip code (5 digits)
   */
  zipcode: (value, message = 'Invalid zip code') => {
    if (!value) return null
    const zipRegex = /^\d{5}(-\d{4})?$/
    return zipRegex.test(value) ? null : message
  },

  /**
   * Numeric only
   */
  numeric: (value, message = 'Must be a number') => {
    if (!value) return null
    return /^\d+$/.test(value.toString()) ? null : message
  },

  /**
   * Alphanumeric only
   */
  alphanumeric: (value, message = 'Only letters and numbers allowed') => {
    if (!value) return null
    return /^[a-zA-Z0-9]+$/.test(value) ? null : message
  }
}

/**
 * Combinador de validadores
 * Ejecuta múltiples validadores en secuencia, retorna primer error
 */
function combineValidators(...validators) {
  return (value) => {
    for (const validator of validators) {
      const error = typeof validator === 'function' ? validator(value) : null
      if (error) return error
    }
    return null
  }
}

window.Validators = Validators
window.combineValidators = combineValidators

/**
 * UseForm - Enhanced
 * Form state management con seguridad, validación y rate limiting
 *
 * Seguridad incluida:
 * - Sanitización automática
 * - Validadores de XSS/SQLi
 * - Rate limiting en submit
 * - CSRF token support
 * - Password strength meter
 *
 * Uso:
 * const form = component.useForm({
 *   email: {
 *     value: '',
 *     validate: [Validators.email],
 *     secure: true  // Auto-sanitize
 *   },
 *   password: {
 *     value: '',
 *     validate: [Validators.password({ min: 8 })],
 *     secure: true
 *   }
 * })
 *
 * form.bind('email', 'input[name="email"]')
 * form.bind('password', 'input[name="password"]')
 * form.onSubmit(handler)
 * form.submit()
 */

class UseForm {
  constructor(schema = {}, component = null, options = {}) {
    this.schema = schema
    this.component = component
    this.values = this._initValues()
    this.errors = {}
    this.touched = {}
    this.dirty = {}
    this.validators = this._extractValidators()
    this.secureFields = this._extractSecureFields()
    this.bindings = new Map()
    this.submitHandler = null
    this.isSubmitting = false

    // Security options
    this.csrfToken = options.csrfToken || null
    this.rateLimitMs = options.rateLimitMs || 2000
    this.lastSubmitTime = 0

    // Password strength tracking
    this.passwordStrength = {}
  }

  /**
   * Initialize values from schema
   */
  _initValues() {
    const values = {}
    for (const [key, field] of Object.entries(this.schema)) {
      values[key] = field.value !== undefined ? field.value : ''
    }
    return values
  }

  /**
   * Extract validators from schema
   */
  _extractValidators() {
    const validators = {}
    for (const [key, field] of Object.entries(this.schema)) {
      if (Array.isArray(field.validate)) {
        validators[key] = field.validate
      }
    }
    return validators
  }

  /**
   * Extract secure fields that need sanitization
   */
  _extractSecureFields() {
    const secure = {}
    for (const [key, field] of Object.entries(this.schema)) {
      if (field.secure === true) {
        secure[key] = true
      }
    }
    return secure
  }

  /**
   * Sanitize value if field is marked secure
   */
  _sanitizeIfNeeded(fieldName, value) {
    if (!this.secureFields[fieldName] || !value) {
      return value
    }

    // Sanitizar: escapar HTML
    const el = document.createElement('div')
    el.textContent = value
    return el.innerHTML
  }

  /**
   * Validate single field
   */
  validateField(name, value = null) {
    const val = value !== null ? value : this.values[name]
    const validators = this.validators[name]

    if (!validators || !Array.isArray(validators)) {
      return null
    }

    for (const validator of validators) {
      try {
        let error = null

        // Si validator es función normal
        if (typeof validator === 'function') {
          error = validator(val)
        }

        if (error) return error
      } catch (e) {
        console.error(`[useForm] validator error for ${name}:`, e)
        return 'Validation error'
      }
    }

    return null
  }

  /**
   * Validate all fields
   */
  validate() {
    const errors = {}
    let isValid = true

    for (const name of Object.keys(this.values)) {
      const error = this.validateField(name)
      if (error) {
        errors[name] = error
        isValid = false
      }
    }

    this.errors = errors
    return { isValid, errors }
  }

  /**
   * Set field value with automatic sanitization
   */
  setValue(name, value) {
    // Sanitizar si es necesario
    const sanitizedValue = this._sanitizeIfNeeded(name, value)
    this.values[name] = sanitizedValue
    this.dirty[name] = true

    // Calcular password strength si es contraseña
    if (name.toLowerCase().includes('password')) {
      this.passwordStrength[name] = this._calculatePasswordStrength(sanitizedValue)
    }

    // Auto-validate if already touched
    if (this.touched[name]) {
      const error = this.validateField(name, sanitizedValue)
      this.errors[name] = error
    }

    // Update component state
    if (this.component) {
      this.component.setState({
        formValues: this.values,
        formErrors: this.errors,
        formTouched: this.touched,
        formDirty: this.dirty,
        passwordStrength: this.passwordStrength
      })
    }
  }

  /**
   * Set field as touched
   */
  setTouched(name) {
    this.touched[name] = true

    // Validate on touch
    const error = this.validateField(name)
    this.errors[name] = error

    if (this.component) {
      this.component.setState({
        formErrors: this.errors,
        formTouched: this.touched
      })
    }
  }

  /**
   * Reset form
   */
  reset() {
    this.values = this._initValues()
    this.errors = {}
    this.touched = {}
    this.dirty = {}
    this.isSubmitting = false
    this.passwordStrength = {}

    if (this.component) {
      this.component.setState({
        formValues: this.values,
        formErrors: this.errors,
        formTouched: this.touched,
        formDirty: this.dirty,
        passwordStrength: this.passwordStrength
      })
    }

    // Reset input elements
    this.bindings.forEach((selector) => {
      const el = document.querySelector(selector)
      if (el) el.value = ''
    })
  }

  /**
   * Calculate password strength (0-100)
   */
  _calculatePasswordStrength(password) {
    if (!password) return 0

    let strength = 0

    // Length
    if (password.length >= 8) strength += 20
    if (password.length >= 12) strength += 10

    // Uppercase
    if (/[A-Z]/.test(password)) strength += 20

    // Numbers
    if (/\d/.test(password)) strength += 20

    // Special characters
    if (/[!@#$%^&*]/.test(password)) strength += 30

    return Math.min(strength, 100)
  }

  /**
   * Get password strength label
   */
  getPasswordStrengthLabel(fieldName) {
    const strength = this.passwordStrength[fieldName] || 0

    if (strength < 30) return 'Weak'
    if (strength < 60) return 'Fair'
    if (strength < 80) return 'Good'
    return 'Strong'
  }

  /**
   * Bind field to input element with mask and sanitization
   */
  bind(fieldName, selector, options = {}) {
    const el = document.querySelector(selector)
    if (!el) {
      console.warn(`[useForm] element not found: ${selector}`)
      return
    }

    const mask = options.mask || null
    const sanitize = this.secureFields[fieldName] || options.sanitize || false

    this.bindings.set(fieldName, selector)

    // Set initial value
    let initialValue = this.values[fieldName] || ''
    if (mask) {
      initialValue = mask(initialValue)
    }
    el.value = initialValue

    // Input event: update value
    el.addEventListener('input', (e) => {
      let value = e.target.value

      // Apply mask if provided
      if (mask) {
        value = mask(value)
        e.target.value = value
      }

      this.setValue(fieldName, value)
    })

    // Blur event: mark as touched
    el.addEventListener('blur', () => {
      this.setTouched(fieldName)
    })

    // Change event (for selects, checkboxes)
    el.addEventListener('change', (e) => {
      if (el.type === 'checkbox') {
        this.setValue(fieldName, e.target.checked)
      } else if (el.type === 'radio') {
        this.setValue(fieldName, e.target.value)
      }
      this.setTouched(fieldName)
    })
  }

  /**
   * Get field error
   */
  getError(name) {
    return this.errors[name] || null
  }

  /**
   * Check if field has error
   */
  hasError(name) {
    return !!this.errors[name]
  }

  /**
   * Check if field is touched
   */
  isTouched(name) {
    return !!this.touched[name]
  }

  /**
   * Check if field is dirty (modified)
   */
  isDirty(name) {
    return !!this.dirty[name]
  }

  /**
   * Get all form values (deep copy)
   */
  getValues() {
    return JSON.parse(JSON.stringify(this.values))
  }

  /**
   * Check if form is valid
   */
  isValid() {
    return this.validate().isValid
  }

  /**
   * Check if form is dirty
   */
  isDirty() {
    return Object.values(this.dirty).some(v => v)
  }

  /**
   * On submit handler
   */
  onSubmit(handler) {
    this.submitHandler = handler
    return this
  }

  /**
   * Check rate limiting
   */
  _checkRateLimit() {
    const now = Date.now()
    if (now - this.lastSubmitTime < this.rateLimitMs) {
      return false
    }
    this.lastSubmitTime = now
    return true
  }

  /**
   * Prepare payload with optional CSRF token
   */
  _preparePayload(values) {
    const payload = { ...values }

    // Add CSRF token if configured
    if (this.csrfToken) {
      payload._csrf = this.csrfToken
    }

    return payload
  }

  /**
   * Handle form submission
   */
  async submit(e) {
    if (e) {
      e.preventDefault()
    }

    if (!this.submitHandler) {
      console.warn('[useForm] no submit handler set')
      return
    }

    // Check rate limiting
    if (!this._checkRateLimit()) {
      console.warn('[useForm] submit rate limited')
      const error = `Please wait ${Math.ceil((this.rateLimitMs - (Date.now() - this.lastSubmitTime)) / 1000)}s before trying again`
      this.errors._form = error
      if (this.component) {
        this.component.setState({ formError: error })
      }
      return
    }

    const { isValid } = this.validate()
    if (!isValid) {
      console.log('[useForm] validation failed')
      return false
    }

    this.isSubmitting = true

    if (this.component) {
      this.component.setState({ formSubmitting: true })
    }

    try {
      const payload = this._preparePayload(this.getValues())
      const result = await this.submitHandler(payload)
      this.isSubmitting = false
      return result
    } catch (error) {
      console.error('[useForm] submit error:', error)
      this.isSubmitting = false
      throw error
    } finally {
      if (this.component) {
        this.component.setState({ formSubmitting: false })
      }
    }
  }

  /**
   * Set CSRF token for form
   */
  setCsrfToken(token) {
    this.csrfToken = token
    return this
  }

  /**
   * Get CSRF token
   */
  getCsrfToken() {
    return this.csrfToken
  }

  /**
   * Debug: print form state
   */
  debug() {
    console.group('[useForm] Debug')
    console.log('Values:', this.getValues())
    console.log('Errors:', this.errors)
    console.log('Touched:', this.touched)
    console.log('Dirty:', this.dirty)
    console.log('Password Strength:', this.passwordStrength)
    console.log('IsValid:', this.isValid())
    console.log('IsDirty:', this.isDirty())
    console.log('IsSubmitting:', this.isSubmitting)
    console.log('CSRF Token:', this.csrfToken ? '✓ Set' : '✗ Not set')
    console.groupEnd()
  }
}

/**
 * Agregar useForm como método en SimpleComponent
 */
if (typeof SimpleComponent !== 'undefined') {
  SimpleComponent.prototype.useForm = function(schema, options = {}) {
    if (!this._useFormInstance) {
      this._useFormInstance = new UseForm(schema, this, options)
    }
    return this._useFormInstance
  }
}

window.UseForm = UseForm

/**
 * DomUtils
 * Utilidades para seguridad y animaciones del DOM
 *
 * Sanitización:
 * const safe = sanitize(userInput)
 *
 * Masks (input formatting):
 * const phoneMask = createMask('+1 (XXX) XXX-XXXX')
 * const masked = phoneMask('1234567890')  // '+1 (123) 456-7890'
 *
 * View Transitions:
 * withViewTransition(() => component.setState({ tab: 'new' }))
 */

/**
 * Sanitize HTML to prevent XSS
 * Convierte caracteres especiales en entities
 */
function sanitize(html) {
  if (!html) return ''
  const el = document.createElement('div')
  el.textContent = html
  return el.innerHTML
}

/**
 * Create input mask formatter
 * Pattern: '+1 (XXX) XXX-XXXX' donde X = digit
 *
 * Ejemplos:
 * - Teléfono: createMask('+1 (XXX) XXX-XXXX')
 * - Tarjeta: createMask('XXXX XXXX XXXX XXXX')
 * - Fecha: createMask('XX/XX/XXXX')
 */
function createMask(pattern) {
  return (value) => {
    if (!value) return ''

    // Extraer solo los caracteres que coinciden con X (ignorar espacios, paréntesis, etc)
    let extracted = ''
    const isDigitPattern = pattern.includes('XXX')
    const isAlphaPattern = pattern.includes('AAA')

    for (const char of value) {
      if (isDigitPattern && /\d/.test(char)) {
        extracted += char
      } else if (isAlphaPattern && /[a-zA-Z0-9]/.test(char)) {
        extracted += char
      } else if (!isDigitPattern && !isAlphaPattern) {
        extracted += char
      }
    }

    // Aplicar el patrón
    let result = ''
    let extractedIndex = 0

    for (let i = 0; i < pattern.length && extractedIndex < extracted.length; i++) {
      if (pattern[i] === 'X' || pattern[i] === 'A') {
        result += extracted[extractedIndex]
        extractedIndex++
      } else {
        result += pattern[i]
      }
    }

    return result
  }
}

/**
 * Predefined masks
 */
const Masks = {
  phone: createMask('+1 (XXX) XXX-XXXX'),
  phoneSimple: createMask('(XXX) XXX-XXXX'),
  creditCard: createMask('XXXX XXXX XXXX XXXX'),
  date: createMask('XX/XX/XXXX'),
  ssn: createMask('XXX-XX-XXXX'),
  zipcode: createMask('XXXXX'),
  currency: (value) => {
    const num = parseFloat(value) || 0
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD'
    }).format(num)
  }
}

/**
 * Animate DOM changes with View Transition API
 * Fallback para navegadores sin soporte
 */
async function withViewTransition(callback) {
  try {
    if (document.startViewTransition) {
      return new Promise((resolve) => {
        const transition = document.startViewTransition(() => {
          callback()
        })
        transition.finished.then(resolve)
      })
    } else {
      // Fallback: ejecutar sin animación
      callback()
      return Promise.resolve()
    }
  } catch (error) {
    console.error('[DomUtils] viewTransition error:', error)
    callback()
    return Promise.resolve()
  }
}

/**
 * Create debounce wrapper for input events
 * Útil para validación/búsqueda en tiempo real
 */
function debounce(func, delay = 300) {
  let timeoutId
  return function(...args) {
    clearTimeout(timeoutId)
    timeoutId = setTimeout(() => func(...args), delay)
  }
}

/**
 * Create throttle wrapper
 */
function throttle(func, limit = 300) {
  let inThrottle
  return function(...args) {
    if (!inThrottle) {
      func(...args)
      inThrottle = true
      setTimeout(() => inThrottle = false, limit)
    }
  }
}

// Export
window.sanitize = sanitize
window.createMask = createMask
window.Masks = Masks
window.withViewTransition = withViewTransition
window.debounce = debounce
window.throttle = throttle

/**
 * DevTools
 * Debugging utilities para SimpleComponent y SimpleStore
 *
 * Acceso global:
 * $exonoor.stores['app'].inspect()
 * $exonoor.components['board'].inspect()
 * $exonoor.devtools.timeline
 */

class DevTools {
    constructor() {
        this.enabled = true
        this.timeline = []
        this.maxTimeline = 100
        this._registerGlobal()
    }

    _registerGlobal() {
        if (typeof window !== 'undefined') {
            window.$exonoor = {
                stores: new Map(),
                components: new Map(),
                devtools: this,
            }
        }
    }

    /**
     * Register store for debugging
     */
    registerStore(name, store) {
        if (typeof window === 'undefined') return
        window.$exonoor.stores.set(name, store)
        this._logTimeline(`Store registered: ${name}`)
    }

    /**
     * Register component for debugging
     */
    registerComponent(name, component) {
        if (typeof window === 'undefined') return
        window.$exonoor.components.set(name, component)
        this._logTimeline(`Component registered: ${name}`)
    }

    /**
     * Log state change
     */
    logStateChange(name, type, prevState, newState) {
        if (!this.enabled) return

        const changes = this._diffObjects(prevState, newState)
        this._logTimeline(`[${type}] ${name}`, changes)

        // Auto-expand for debugging
        if (typeof console !== 'undefined' && console.debug) {
            console.debug(`[${type}] ${name}`, { from: prevState, to: newState })
        }
    }

    /**
     * Log action
     */
    logAction(name, action, payload) {
        if (!this.enabled) return
        this._logTimeline(`[Action] ${name}.${action}`, payload)
    }

    /**
     * Log performance
     */
    logPerformance(name, duration) {
        if (!this.enabled) return
        const color = duration < 16 ? '🟢' : duration < 50 ? '🟡' : '🔴'
        this._logTimeline(`${color} ${name} (${duration}ms)`)
    }

    /**
     * Internal: add to timeline
     */
    _logTimeline(message, data = null) {
        const entry = {
            timestamp: new Date(),
            message,
            data,
        }

        this.timeline.push(entry)

        if (this.timeline.length > this.maxTimeline) {
            this.timeline.shift()
        }
    }

    /**
     * Diff two objects
     */
    _diffObjects(prev, curr) {
        const changes = {}

        for (const key in curr) {
            if (prev[key] !== curr[key]) {
                changes[key] = { from: prev[key], to: curr[key] }
            }
        }

        return changes
    }

    /**
     * Print timeline
     */
    printTimeline(limit = 20) {
        console.group('[DevTools Timeline]')

        const entries = this.timeline.slice(-limit)

        entries.forEach((entry) => {
            const time = entry.timestamp.toLocaleTimeString()
            console.log(`${time} ${entry.message}`, entry.data || '')
        })

        console.groupEnd()
    }

    /**
     * Export timeline
     */
    exportTimeline() {
        return this.timeline.map((entry) => ({
            ...entry,
            timestamp: entry.timestamp.toISOString(),
        }))
    }

    /**
     * Clear timeline
     */
    clearTimeline() {
        this.timeline = []
    }

    /**
     * Get stats
     */
    getStats() {
        return {
            stores: window.$exonoor?.stores.size || 0,
            components: window.$exonoor?.components.size || 0,
            timelineLength: this.timeline.length,
            enabled: this.enabled,
        }
    }

    /**
     * Print stats
     */
    printStats() {
        const stats = this.getStats()
        console.group('[DevTools Stats]')
        console.table(stats)
        console.groupEnd()
    }

    /**
     * Inspect all stores
     */
    inspectStores() {
        if (!window.$exonoor?.stores.size) {
            console.log('[DevTools] No stores registered')
            return
        }

        console.group('[DevTools Stores]')

        window.$exonoor.stores.forEach((store, name) => {
            console.group(`Store: ${name}`)
            console.log('State:', store.getState())
            console.log('Subscribers:', store._subscribers.size)
            console.log('History:', store._history.length)
            console.groupEnd()
        })

        console.groupEnd()
    }

    /**
     * Inspect all components
     */
    inspectComponents() {
        if (!window.$exonoor?.components.size) {
            console.log('[DevTools] No components registered')
            return
        }

        console.group('[DevTools Components]')

        window.$exonoor.components.forEach((component, name) => {
            console.group(`Component: ${name}`)
            console.log('State:', component.state)
            console.log('Mounted:', component._mounted)
            console.log('Subscribers:', component._subscribers.length)
            console.log('DOM:', component.el)
            console.groupEnd()
        })

        console.groupEnd()
    }

    /**
     * Quick debug: show everything
     */
    debug() {
        console.clear()
        this.printStats()
        console.log('')
        this.inspectStores()
        console.log('')
        this.inspectComponents()
        console.log('')
        this.printTimeline()
    }

    /**
     * Help: show available commands
     */
    help() {
        console.log(`
    EliteUI DevTools Commands:

    Global access: window.$exonoor

    Stores:
      $exonoor.stores.get('name')          // Get store by name
      $exonoor.stores.forEach(...)         // Iterate stores

    Components:
      $exonoor.components.get('name')      // Get component by name
      $exonoor.components.forEach(...)     // Iterate components

    DevTools:
      $exonoor.devtools.debug()            // Full debug output
      $exonoor.devtools.help()             // This help
      $exonoor.devtools.inspectStores()    // All stores
      $exonoor.devtools.inspectComponents() // All components
      $exonoor.devtools.printTimeline()    // Event timeline
      $exonoor.devtools.printStats()       // Statistics
      $exonoor.devtools.clearTimeline()    // Clear timeline
      $exonoor.devtools.enabled = false    // Disable logging

    Example:
      const store = $exonoor.stores.get('app')
      store.debug()                        // Print store state

      const comp = $exonoor.components.get('board')
      comp.state                           // Get component state
      comp.setState({ ... })               // Update state
    `)
    }
}

// Auto-create global instance
const devTools = new DevTools()

// Extend SimpleComponent to register itself (mount only, no setState hook to prevent recursion)
if (typeof SimpleComponent !== 'undefined') {
    const originalMount = SimpleComponent.prototype.mount

    SimpleComponent.prototype.mount = function () {
        // Register in devtools if has name
        if (this.constructor.name && this.constructor.name !== 'SimpleComponent') {
            const displayName = this.name || this.constructor.name
            devTools.registerComponent(displayName, this)
        }

        return originalMount.call(this)
    }
}

// Extend SimpleStore to register itself (no setState hook to prevent recursion)
if (typeof SimpleStore !== 'undefined') {
    SimpleStore.prototype.setName = function (name) {
        this._name = name
        devTools.registerStore(name, this)
        return this
    }
}

window.DevTools = DevTools
window.$exonoor = window.$exonoor || { stores: new Map(), components: new Map(), devtools }

// Print help on first access
if (typeof console !== 'undefined') {
    console.log('%c[DevTools] EliteUI debugging enabled. Type $exonoor.devtools.help() for commands.', 'color: #4f6fff; font-weight: bold')
}

/**
 * Analytics
 * Wrapper agnóstico para GA4, Mixpanel, Segment, etc
 *
 * Uso:
 * const analytics = new Analytics({ provider: 'ga4', id: 'G-XXXXX' })
 * analytics.trackEvent('button_click', { button: 'submit' })
 * analytics.trackPageView('/dashboard')
 */

class Analytics {
  constructor(options = {}) {
    this.provider = options.provider || 'ga4' // 'ga4', 'gtm', 'mixpanel', 'segment', 'custom'
    this.id = options.id || null
    this.enabled = options.enabled !== false
    this.userId = options.userId || null
    this.sessionId = this._generateSessionId()
    this.events = []
    this.maxEvents = 100

    if (this.enabled) {
      this._initProvider()
    }
  }

  /**
   * Initialize analytics provider
   */
  _initProvider() {
    if (!this.id) {
      console.warn('[Analytics] No ID provided for provider:', this.provider)
      return
    }

    switch (this.provider) {
      case 'ga4':
        this._initGA4()
        break
      case 'gtm':
        this._initGTM()
        break
      case 'mixpanel':
        this._initMixpanel()
        break
      case 'segment':
        this._initSegment()
        break
      default:
        console.warn('[Analytics] Unknown provider:', this.provider)
    }
  }

  /**
   * Initialize Google Analytics 4
   */
  _initGA4() {
    const script = document.createElement('script')
    script.async = true
    script.src = `https://www.googletagmanager.com/gtag/js?id=${this.id}`
    document.head.appendChild(script)

    window.dataLayer = window.dataLayer || []
    window.gtag = function() {
      window.dataLayer.push(arguments)
    }
    window.gtag('js', new Date())
    window.gtag('config', this.id)
  }

  /**
   * Initialize Google Tag Manager
   */
  _initGTM() {
    const script = document.createElement('script')
    script.async = true
    script.src = `https://www.googletagmanager.com/gtm.js?id=${this.id}`
    document.head.appendChild(script)

    window.dataLayer = window.dataLayer || []
    window.dataLayer.push({
      'gtm.start': new Date().getTime(),
      event: 'gtm.js'
    })
  }

  /**
   * Initialize Mixpanel
   */
  _initMixpanel() {
    const script = document.createElement('script')
    script.textContent = `
      (function(f,b){if(!b.__SV){var a,e,i,g;window.mixpanel=b;b._i=[];b.init=function(a,e,d){function f(b,h){var a=h.split(".");2==a.length&&(b=b[a[0]],h=a[1]);b[h]=function(){b.push([h].concat(Array.prototype.slice.call(arguments,0)))}}var c=b;"undefined"!==typeof d?c=b[d]=[]:d="mixpanel";c.people=c.people||[];c.toString=function(b){var a="mixpanel";"undefined"!==typeof d&&"mixpanel"!==d&&(a+="."+d);b||(a+=" (stub)");return a};c.people.toString=function(){return c.toString(1)+".people (stub)"};i="disable time_event track track_pageview track_links track_forms register register_once unregister identify name_tag set_config reset opt_in_tracking opt_out_tracking has_opted_in_tracking has_opted_out_tracking clear_opt_in_tracking_cookie clear_opt_out_tracking_cookie getEditorParams".split(" ");for(g=0;g<i.length;g++)f(c,i[g]);b._i.push([a,e,d])};b.__SV=1.2}})(document,window.mixpanel||[]);
      mixpanel.init("${this.id}");
    `
    document.head.appendChild(script)
  }

  /**
   * Initialize Segment
   */
  _initSegment() {
    const script = document.createElement('script')
    script.textContent = `
      !function(){var analytics=window.analytics=window.analytics||[];if(!analytics.initialize)if(analytics.invoked)window.console&&console.error&&console.error("Segment snippet included twice.");else{analytics.invoked=!0;analytics.methods=["trackSubmit","trackClick","trackLink","trackForm","pageview","identify","reset","group","track","ready","alias","debug","page","once","off","on","addSourceMiddleware","addIntegrationMiddleware","setAnonymousId","addDestinationMiddleware"];analytics.factory=function(e){return function(){var t=Array.prototype.slice.call(arguments);t.unshift(e);analytics.push(t);return analytics}};for(var e=0;e<analytics.methods.length;e++){var t=analytics.methods[e];analytics[t]=analytics.factory(t)}analytics.load=function(e,t){var n=document.createElement("script");n.type="text/javascript";n.async=!0;n.src="https://cdn.segment.com/analytics.js/v1/"+e+"/analytics.min.js";var a=document.getElementsByTagName("script")[0];a.parentNode.insertBefore(n,a);analytics._loadOptions=t};analytics._writeKey="${this.id}";analytics.SNIPPET_VERSION="4.13.1";
      analytics.load("${this.id}");
      analytics.page();
    }}();
    `
    document.head.appendChild(script)
  }

  /**
   * Track event
   */
  trackEvent(eventName, eventData = {}) {
    if (!this.enabled) return

    const event = {
      name: eventName,
      data: eventData,
      timestamp: new Date().toISOString(),
      sessionId: this.sessionId,
      userId: this.userId
    }

    this.events.push(event)
    if (this.events.length > this.maxEvents) {
      this.events.shift()
    }

    switch (this.provider) {
      case 'ga4':
        window.gtag?.('event', eventName, eventData)
        break
      case 'gtm':
        window.dataLayer?.push({ event: eventName, ...eventData })
        break
      case 'mixpanel':
        window.mixpanel?.track(eventName, eventData)
        break
      case 'segment':
        window.analytics?.track(eventName, eventData)
        break
    }

    console.debug('[Analytics] Event tracked:', eventName, eventData)
    return this
  }

  /**
   * Track page view
   */
  trackPageView(path, title) {
    if (!this.enabled) return

    const pageData = {
      path: path || window.location.pathname,
      title: title || document.title,
      url: window.location.href,
      referrer: document.referrer
    }

    switch (this.provider) {
      case 'ga4':
        window.gtag?.('event', 'page_view', pageData)
        break
      case 'gtm':
        window.dataLayer?.push({ event: 'pageview', ...pageData })
        break
      case 'mixpanel':
        window.mixpanel?.track('$pageview', pageData)
        break
      case 'segment':
        window.analytics?.page(title, pageData)
        break
    }

    return this
  }

  /**
   * Identify user
   */
  identifyUser(userId, traits = {}) {
    if (!this.enabled) return

    this.userId = userId

    const data = { id: userId, ...traits }

    switch (this.provider) {
      case 'ga4':
        window.gtag?.('event', 'login', { method: 'EliteUI' })
        window.gtag?.('config', this.id, { user_id: userId })
        break
      case 'gtm':
        window.dataLayer?.push({ event: 'identify', userId, ...traits })
        break
      case 'mixpanel':
        window.mixpanel?.identify(userId)
        window.mixpanel?.people.set(traits)
        break
      case 'segment':
        window.analytics?.identify(userId, traits)
        break
    }

    return this
  }

  /**
   * Track form submission
   */
  trackFormSubmit(formName, formData = {}) {
    return this.trackEvent('form_submit', {
      form_name: formName,
      form_fields: Object.keys(formData).length,
      timestamp: Date.now()
    })
  }

  /**
   * Track button click
   */
  trackButtonClick(buttonName, context = {}) {
    return this.trackEvent('button_click', {
      button_name: buttonName,
      ...context
    })
  }

  /**
   * Track error
   */
  trackError(errorName, errorData = {}) {
    return this.trackEvent('error', {
      error_name: errorName,
      error_message: errorData.message,
      error_stack: errorData.stack,
      ...errorData
    })
  }

  /**
   * Track custom metric
   */
  trackMetric(metricName, value) {
    return this.trackEvent('custom_metric', {
      metric_name: metricName,
      metric_value: value
    })
  }

  /**
   * Generate session ID
   */
  _generateSessionId() {
    return `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
  }

  /**
   * Get event history
   */
  getEventHistory() {
    return [...this.events]
  }

  /**
   * Clear event history
   */
  clearEventHistory() {
    this.events = []
    return this
  }

  /**
   * Debug: print analytics state
   */
  debug() {
    console.group('[Analytics]')
    console.log('Provider:', this.provider)
    console.log('ID:', this.id)
    console.log('Enabled:', this.enabled)
    console.log('User ID:', this.userId)
    console.log('Session ID:', this.sessionId)
    console.log('Events:', this.events.length)
    console.table(this.events.slice(-10))
    console.groupEnd()
  }
}

window.Analytics = Analytics

/**
 * Permissions System
 * Lightweight role-based access control
 * 
 * Usage:
 * $permissions.define('admin', ['read', 'write', 'delete'])
 * $permissions.grant('john', 'admin')
 * $permissions.has('john', 'write') // true
 * 
 * Or with roles config:
 * $permissions.define('admin', ['users.read', 'users.write'])
 * $permissions.define('user', ['users.read'])
 */

class Permissions {
    constructor() {
        this._roles = new Map()
        this._users = new Map()
        this._currentUser = null
    }

    /**
     * Define a role with its permissions
     */
    define(role, permissions) {
        this._roles.set(role, new Set(permissions))
    }

    /**
     * Grant role to user
     */
    grant(userId, role) {
        this._users.set(userId, role)
        if (!this._currentUser) {
            this._currentUser = userId
        }
    }

    /**
     * Revoke role from user
     */
    revoke(userId) {
        this._users.delete(userId)
    }

    /**
     * Set current user
     */
    setCurrentUser(userId) {
        this._currentUser = userId
    }

    /**
     * Get current user
     */
    getCurrentUser() {
        return this._currentUser
    }

    /**
     * Check if user has permission
     */
    has(userId, permission) {
        const role = this._users.get(userId)
        if (!role) return false
        
        const permissions = this._roles.get(role)
        if (!permissions) return false

        // Check exact permission or wildcard (e.g., 'admin.*')
        if (permissions.has(permission)) return true
        
        // Check wildcard permission
        const [namespace] = permission.split('.')
        if (permissions.has(`${role}.*`)) return true
        if (permissions.has(`${namespace}.*`)) return true
        
        return false
    }

    /**
     * Check if current user has permission
     */
    can(permission) {
        return this.has(this._currentUser, permission)
    }

    /**
     * Check if user has role
     */
    is(userId, role) {
        return this._users.get(userId) === role
    }

    /**
     * Check if current user is role
     */
    isRole(role) {
        return this.is(this._currentUser, role)
    }

    /**
     * Get user role
     */
    getRole(userId) {
        return this._users.get(userId)
    }

    /**
     * Get all permissions for user
     */
    getPermissions(userId) {
        const role = this._users.get(userId)
        if (!role) return []
        const permissions = this._roles.get(role)
        return permissions ? [...permissions] : []
    }

    /**
     * Remove role definition
     */
    removeRole(role) {
        this._roles.delete(role)
    }

    /**
     * Clear all data
     */
    reset() {
        this._roles.clear()
        this._users.clear()
        this._currentUser = null
    }
}

const $permissions = new Permissions()
window.$permissions = $permissions
window.Permissions = Permissions

// Default roles (optional - can be removed)
$permissions.define('guest', ['read'])
$permissions.define('user', ['read', 'profile.read'])
$permissions.define('admin', ['read', 'write', 'delete', 'admin.access'])

console.log('[$permissions] Role-based permissions ready')

/**
 * Env - Environment Variables Reader
 * Reads from window.ENV or meta tags
 * 
 * Usage:
 * // In HTML: <meta name="env" data-api-url="https://api.example.com" data-api-key="abc123">
 * // Or set window.ENV before loading this script
 * 
 * window.ENV = {
 *   API_URL: 'https://api.example.com',
 *   API_KEY: 'abc123'
 * }
 * 
 * const apiUrl = $env('API_URL')
 */

class Env {
    constructor() {
        this._vars = {}
        this._loaded = false
    }

    /**
     * Load env from meta tags or window.ENV
     */
    load() {
        if (this._loaded) return

        // Try window.ENV first
        if (window.ENV && typeof window.ENV === 'object') {
            this._vars = { ...window.ENV }
        }

        // Try meta tags
        const meta = document.querySelector('meta[name="env"]')
        if (meta) {
            const data = meta.dataset
            Object.keys(data).forEach(key => {
                // Convert kebab-case to UPPER_SNAKE_CASE
                const envKey = key.replace(/-/g, '_').toUpperCase()
                this._vars[envKey] = data[key]
            })
        }

        // Try script tag (inline config)
        const config = document.querySelector('script[type="env/config"]')
        if (config) {
            try {
                const data = JSON.parse(config.textContent)
                this._vars = { ...this._vars, ...data }
            } catch (e) {
                console.warn('[Env] Invalid config JSON')
            }
        }

        this._loaded = true
    }

    /**
     * Get env variable
     * @param {string} key - Variable name
     * @param {any} defaultValue - Default if not found
     */
    get(key, defaultValue = null) {
        if (!this._loaded) this.load()
        return this._vars[key] ?? defaultValue
    }

    /**
     * Check if variable exists
     */
    has(key) {
        if (!this._loaded) this.load()
        return key in this._vars
    }

    /**
     * Get all variables
     */
    all() {
        if (!this._loaded) this.load()
        return { ...this._vars }
    }
}

const $env = new Env()
window.$env = $env
window.Env = Env

/**
 * $schema - Mini Zod para validación de schemas
 * 
 * Uso:
 * 
 * const UserSchema = $schema({
 *   name: $string().min(2).max(50),
 *   email: $string().email(),
 *   age: $number().min(0).max(150),
 *   password: $string().min(8).pattern(/[A-Z]/, 'must have uppercase'),
 *   isActive: $boolean(),
 *   tags: $array($string()),
 *   address: $object({
 *     street: $string(),
 *     city: $string()
 *   }).optional()
 * })
 * 
 * const result = UserSchema.parse({
 *   name: 'Juan',
 *   email: 'juan@example.com',
 *   age: 25
 * })
 * 
 * if (result.error) {
 *   console.log('Validation failed:', result.errors)
 * } else {
 *   console.log('Valid!', result.data)
 * }
 */

// Tipos base
const $string = (defaultValue = '') => createSchema('string', { default: defaultValue })
const $number = (defaultValue = 0) => createSchema('number', { default: defaultValue })
const $boolean = (defaultValue = false) => createSchema('boolean', { default: defaultValue })
const $array = (schema) => createSchema('array', { schema })
const $object = (fields) => createSchema('object', { fields })
const $enum = (...values) => createSchema('enum', { values })
const $optional = (schema) => createSchema(schema._type, { ...schema._opts, optional: true })

function createSchema(type, opts = {}) {
  const schema = {
    _type: type,
    _opts: opts,
    _rules: [],

    // String/Number rules
    min(len) {
      this._rules.push({ test: 'min', value: len, message: `Minimum ${len} characters` })
      return this
    },
    max(len) {
      this._rules.push({ test: 'max', value: len, message: `Maximum ${len} characters` })
      return this
    },
    pattern(regex, message = 'Invalid format') {
      this._rules.push({ test: 'pattern', value: regex, message })
      return this
    },
    email(message = 'Invalid email') {
      this._rules.push({ test: 'email', message })
      return this
    },
    url(message = 'Invalid URL') {
      this._rules.push({ test: 'url', message })
      return this
    },
    required(message = 'Required') {
      this._opts.requiredMessage = message
      return this
    },
    optional() {
      this._opts.optional = true
      return this
    },
    default(value) {
      this._opts.default = value
      return this
    },

    // Validate
    parse(value) {
      return validate(value, this)
    },

    // Shorthand for common
    minLength: function(len) { return this.min(len) },
    maxLength: function(len) { return this.max(len) }
  }

  return schema
}

// Validación principal
function validate(value, schema) {
  const errors = []

  // Check optional
  if (value === undefined || value === null) {
    if (schema._opts.optional) {
      return { error: false, data: schema._opts.default ?? null, errors: [] }
    }
    if (schema._opts.default !== undefined) {
      return { error: false, data: schema._opts.default, errors: [] }
    }
    return { error: true, data: null, errors: [schema._opts.requiredMessage || 'Required'] }
  }

  // Type validation
  if (schema._type === 'string' && typeof value !== 'string') {
    return { error: true, data: null, errors: ['Expected string'] }
  }

  if (schema._type === 'number' && typeof value !== 'number') {
    return { error: true, data: null, errors: ['Expected number'] }
  }

  if (schema._type === 'boolean' && typeof value !== 'boolean') {
    return { error: true, data: null, errors: ['Expected boolean'] }
  }

  if (schema._type === 'array' && !Array.isArray(value)) {
    return { error: true, data: null, errors: ['Expected array'] }
  }

  if (schema._type === 'object' && (typeof value !== 'object' || value === null || Array.isArray(value))) {
    return { error: true, data: null, errors: ['Expected object'] }
  }

  if (schema._type === 'enum') {
    if (!schema._opts.values.includes(value)) {
      return { error: true, data: null, errors: [`Must be one of: ${schema._opts.values.join(', ')}`] }
    }
    return { error: false, data: value, errors: [] }
  }

  // String rules
  if (schema._type === 'string') {
    for (const rule of schema._rules) {
      if (rule.test === 'min' && value.length < rule.value) {
        errors.push(rule.message || `Minimum ${rule.value} characters`)
      }
      if (rule.test === 'max' && value.length > rule.value) {
        errors.push(rule.message || `Maximum ${rule.value} characters`)
      }
      if (rule.test === 'pattern' && !rule.value.test(value)) {
        errors.push(rule.message)
      }
      if (rule.test === 'email') {
        const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
        if (!emailRegex.test(value)) errors.push(rule.message)
      }
      if (rule.test === 'url') {
        try { new URL(value) } catch { errors.push(rule.message) }
      }
    }
  }

  // Number rules
  if (schema._type === 'number') {
    for (const rule of schema._rules) {
      if (rule.test === 'min' && value < rule.value) {
        errors.push(rule.message || `Minimum ${rule.value}`)
      }
      if (rule.test === 'max' && value > rule.value) {
        errors.push(rule.message || `Maximum ${rule.value}`)
      }
    }
  }

  // Array rules
  if (schema._type === 'array' && schema._opts.schema) {
    for (let i = 0; i < value.length; i++) {
      const itemResult = validate(value[i], schema._opts.schema)
      if (itemResult.error) {
        errors.push(`[${i}]: ${itemResult.errors.join(', ')}`)
      }
    }
  }

  // Object rules
  if (schema._type === 'object' && schema._opts.fields) {
    for (const [key, fieldSchema] of Object.entries(schema._opts.fields)) {
      const result = validate(value[key], fieldSchema)
      if (result.error) {
        errors.push(`${key}: ${result.errors.join(', ')}`)
      }
    }
  }

  if (errors.length > 0) {
    return { error: true, data: null, errors }
  }

  return { error: false, data: value, errors: [] }
}

// Combinación de schemas
const $merge = (...schemas) => {
  const allFields = {}
  for (const s of schemas) {
    if (s._opts.fields) {
      Object.assign(allFields, s._opts.fields)
    }
  }
  return $object(allFields)
}

// Parseo seguro que no lanza
const $safeParse = (schema, data) => {
  try {
    return schema.parse(data)
  } catch (e) {
    return { error: true, data: null, errors: [e.message] }
  }
}

// $schema function - creates a schema from fields definition
const $schema = (fields) => {
  return $object(fields)
}

// Shorthand exports (attach to window immediately for use within bundle)
window.$schema = $schema
window.$string = $string
window.$number = $number
window.$boolean = $boolean
window.$array = $array
window.$object = $object
window.$enum = $enum
window.$optional = $optional
window.$merge = $merge
window.$safeParse = $safeParse

console.log('[$schema] Mini Zod ready')

/**
 * EliteUI - Simple i18n System
 * Lightweight internationalization with JSON files
 */

class I18n {
    constructor(defaultLocale = 'en') {
        this.locale = defaultLocale
        this.translations = {}
        this.fallback = {}
    }

    /**
     * Load translations from a JSON object
     * @param {Object} data - Translation data { en: {...}, es: {...} }
     */
    load(data) {
        this.translations = data
        this.fallback = data[this.locale] || {}
    }

    /**
     * Load translations from external JSON files
     * @param {string} path - Base path to lang files (e.g., 'lang/')
     * @param {Array} locales - Available locales ['en', 'es', 'pt']
     */
    async loadFromFiles(path = 'lang/', locales = ['en', 'es']) {
        const promises = locales.map(async (locale) => {
            try {
                const response = await fetch(`${path}${locale}.json`)
                if (response.ok) {
                    this.translations[locale] = await response.json()
                }
            } catch (e) {
                console.warn(`[I18n] Failed to load ${path}${locale}.json`)
            }
        })
        await Promise.all(promises)
        this.fallback = this.translations[this.locale] || {}
    }

    /**
     * Set current locale
     * @param {string} locale - Locale code (en, es, pt)
     */
    setLocale(locale) {
        this.locale = locale
        this.fallback = this.translations[locale] || {}
        localStorage.setItem('elite-locale', locale)
    }

    /**
     * Get current locale
     */
    getLocale() {
        return this.locale
    }

    /**
     * Translate a key
     * @param {string} key - Dot notation key (e.g., 'home.title')
     * @param {Object} params - Replace params {{name}}
     * @returns {string}
     */
    t(key, params = {}) {
        let text = this.fallback[key] || key

        // Try other loaded locales as fallback
        if (text === key) {
            for (const locale in this.translations) {
                if (this.translations[locale][key]) {
                    text = this.translations[locale][key]
                    break
                }
            }
        }

        // Replace params
        Object.keys(params).forEach(param => {
            text = text.replace(new RegExp(`{{${param}}}`, 'g'), params[param])
        })

        return text
    }

    /**
     * Get all translations for current locale
     */
    getTranslations() {
        return this.fallback
    }
}

// Global instance
window.I18n = I18n
window.$t = null

// Auto-init
window.initI18n = function(defaultLocale = 'en') {
    const savedLocale = localStorage.getItem('elite-locale') || defaultLocale
    window.$i18n = new I18n(savedLocale)
    window.$t = window.$i18n.t.bind(window.$i18n)
    return window.$i18n
}

